-- W2 catalog seed batch4_ornamentals_houseplants — 24 cited profiles (generated from PlantAppPlanner scratch/catalog/profiles; sources embedded per row).
-- Upsert: already-seeded Slice-1 ids are enriched in place (version bump), never duplicated.
insert into public.plant_profiles (
  id, scientific_name, common_names, category, growth_habit, requires_support, self_fruitful, pollination_partners_required, watering_profile, feeding_profile, container_profile, light_profile, temperature_profile, seasonality, common_issues, vertical_suitability, source, version, last_reviewed_at
) values
  ('aglaonema-commutatum', 'Aglaonema commutatum', array['Chinese evergreen','Philippine evergreen','Golden evergreen']::text[], 'houseplant', 'upright', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.8,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":28,"containerLeachAdjustment":1,"preferredNpk":"balanced (e.g. 10-10-10) at half strength"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":4,"idealMaxLiters":10,"soilMixTags":["soilless-mix","peaty","well-draining","extra-humus"]}'::jsonb, '{"targetSunHours":3,"minSunHours":0,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":7,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"dormancyMonths":[10,11,12,1,2]}'::jsonb, array['Root rot from overwatering or poor drainage — the most common failure mode','Leaf yellowing from overwatering','Leaf browning/edge burn from very dry air, drafts, or cold water','Leaf edge burn from excessive fertilizer','Leaf scorch in direct sun — keep in indirect light','Pests: mealybugs, aphids, scale, spider mites','Cold injury to foliage below ~7 C (45 F); keep above ~15 C (60 F) in winter','Contains calcium oxalate crystals — toxic to pets (dogs/cats) and irritating sap; keep out of reach','Becomes leggy with age as stems elongate']::text[], 0.2, '[{"citation":"Clemson University HGIC, ''Chinese Evergreen (Aglaonema) Care, Cultivation & Growing Guide'' — low to moderate indirect light; keep soil moist but not wet, let top 1-2 in dry between waterings; optimal 68-80 F, sensitive below 50 F; soilless mix with extra humus; excessive fertilizer causes leaf edge burn; pests mealybugs/aphids/scale/mites; toxic to pets.","url":"https://hgic.clemson.edu/factsheet/chinese-evergreen-aglaonema-care-cultivation-growing-guide/","field":"wateringProfile"},{"citation":"NC State Extension Gardener Plant Toolbox, ''Aglaonema'' — deep shade (<2 h direct sun) to partial shade (2-6 h); erect and bushy habit; keep mix moist spring-fall, reduce in winter; prefers 70-80 F daytime, intolerant of cold; calcium oxalate toxicity.","url":"https://plants.ces.ncsu.edu/plants/aglaonema/","field":"lightProfile"},{"citation":"UF/IFAS publication FPS25/FP025, ''Aglaonema spp.: Chinese Evergreen'' — grows in shade, leaf scorch in sun; let soil dry slightly a few days between waterings; foliage injury below 45 F; USDA zones 10B-11B; 1-3 ft tall/wide; suitable for containers; root rot from excess moisture.","url":"https://ask.ifas.ufl.edu/publication/FP025","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, ''Aglaonema commutatum'' — diffused sun or good indirect light; consistent moisture spring-fall, reduce early fall to late winter but never let soil fully dry; 60 F recommended winter minimum; well-drained peaty mix; 1-1.5 ft tall/wide; zones 10-12; rots if overwatered, leaves brown in dry air/drafts.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=276174","field":"seasonality"},{"citation":"University of Illinois Extension, ''Favorite houseplants of a horticulturist'' — fertilize aglaonema every four weeks with balanced houseplant fertilizer, every six weeks in winter; slow grower, rarely needs repotting; prefers slightly moist soil; brighter leaf color needs more light.","url":"https://extension.illinois.edu/blogs/flowers-fruits-and-frass/2022-01-24-favorite-houseplants-horticulturist","field":"feedingProfile"},{"citation":"Confidence note: no authoritative source states a numeric watering interval; baseIntervalDays=7 is a conservative estimate derived from Clemson''s ''let top 1-2 inches dry'' guidance for a slow-growing indoor aroid. Container liters (4 L min ≈ 6-8 in pot) estimated from MOBOT/UF mature size of 1-3 ft for a compact, slow-growing plant. heatStressC=32 estimated from Clemson''s 68-80 F optimum upper bound. Sun-hour values translate shade/indirect-light guidance (NCSU deep shade to 2-6 h partial shade) into the schema''s hours/day.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('antirrhinum-majus', 'Antirrhinum majus', array['Snapdragon','Common Snapdragon','Garden Snapdragon']::text[], 'ornamental', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"containerLeachAdjustment":0.75,"preferredNpk":"balanced all-purpose (e.g. 10-10-10)"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":6,"idealMaxLiters":12,"soilMixTags":["well-drained","rich-organic-matter","moist"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-5,"heatStressC":27,"frostSensitive":false}'::jsonb, '{"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Antirrhinum rust is a significant disease — avoid overhead watering and remove infected foliage','Powdery mildew, downy mildew, fungal leaf spots, wilts, and root rots in poorly drained or humid conditions','Aphids, whiteflies, and leafminers','Bloom stalls and plants languish in summer heat — performs best in cool seasons (spring/fall)','Tall cut-flower cultivars need staking or netting; dwarf bedding types do not','Deadhead spent spikes to prolong flowering and prevent the plant from setting seed and dying back','A tender short-lived perennial usually grown as a hardy annual; tolerates light frost but is killed by very hard freezes']::text[], 0.2, '[{"citation":"North Carolina State Extension Gardener Plant Toolbox — Antirrhinum majus: full sun (6+ hours) to partial shade (2–6 hours); moist, rich, well-drained soil; good container plant; tall plants may need staking; low drought tolerance, languishes in summer heat; zones 7a–10b; significant rust susceptibility.","url":"https://plants.ces.ncsu.edu/plants/antirrhinum-majus/","field":"lightProfile"},{"citation":"NC State Plant Toolbox — ''low drought tolerance'' and need for consistently moist, well-drained soil informs the short watering interval and low drying tolerance.","url":"https://plants.ces.ncsu.edu/plants/antirrhinum-majus/","field":"wateringProfile"},{"citation":"Clemson HGIC, ''Snapdragons for Fall Blooms'' — plant in full to part sun; water on a regular basis; fertilize with an all-purpose fertilizer after cutting back; taller varieties require support; perennial only in zones 9+; deadhead and cut tall types back to 6 inches after flowering.","url":"https://hgic.clemson.edu/snapdragons-for-fall-blooms/","field":"feedingProfile"},{"citation":"University of Illinois Extension, Flowers: Snapdragon — hardy annual, very cold tolerant, performs in cool seasons until a very hard frost kills it; full sun to light shade; moist well-drained soil; blooms May–October; tall cultivars may need staking.","url":"https://extension.illinois.edu/flowers/snapdragon","field":"temperatureProfile"},{"citation":"University of Illinois Extension, Container Gardens: Fertilizing — reapplying fertilizer every two weeks provides adequate nutrition for most containers (basis for the 14-day feeding interval).","url":"https://extension.illinois.edu/container-gardens/fertilizing","field":"feedingProfile"},{"citation":"Mississippi State University Extension, ''Snapdragon (Antirrhinum majus) for the Farmer Florist'' — full sun to partial shade; space 4–12 in; ideal night temps above 60F (16C); drip irrigation preferred since overhead watering increases disease; major diseases rust, botrytis, powdery/downy mildew, root rots; pests aphids, whiteflies, leafminers.","url":"https://extension.msstate.edu/publications/snapdragon-antirrhinum-majus-for-the-farmer-florist","field":"commonIssues"},{"citation":"RHS, Antirrhinum majus — full sun, well-drained soil; hardiness H2 (1–5C minimum for reliable overwintering of tender stock); flowers late spring to autumn; susceptible to antirrhinum rust, powdery mildews, aphids; deadheading prolongs flowering.","url":"https://www.rhs.org.uk/plants/69565/antirrhinum-majus/details","field":"seasonality"},{"citation":"Confidence note: no single extension page gives an exact container-watering interval or minimum pot volume for snapdragons. baseIntervalDays=3 is a conservative reading of ''regular, consistent moisture / ~1 inch per week, more in containers'' guidance; recommendedMinLiters=4 corresponds to a standard 8-inch (20 cm) pot commonly used for bedding annuals; coldHardyMinC=-5 is a conservative light-frost tolerance consistent with ''very cold tolerant hardy annual killed by very hard frost'' (Illinois) and RHS H2; heatStressC=27 reflects ''languishes in summer heat'' (NCSU) without a published exact threshold.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('begonia-semperflorens', 'Begonia semperflorens', array['Begonia','Wax Begonia','Fibrous Begonia','Bedding Begonia','Wax Leaf Begonia']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":30,"preferredNpk":"balanced (e.g. 10-10-10) at planting, then bloom formula higher in phosphorus than nitrogen; in containers RHS advises weekly high-potassium liquid feed in summer"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":10,"soilMixTags":["well-drained","high-organic-matter","quality-potting-mix","slightly-acidic-ph-5.5-6.5"]}'::jsonb, '{"targetSunHours":4,"minSunHours":2,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":0,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[5,6,7,8,9,10]}'::jsonb, array['Root rot from overwatering or soggy soil — begonias are highly susceptible; ensure drainage holes and let soil dry slightly between waterings','Powdery mildew and Botrytis blight — water at the base of the plant early in the day and keep good air circulation','Mealybugs, thrips, spider mites, slugs and snails; may be sensitive to insecticidal soaps','Leaf scorch on green-leaved cultivars in hot afternoon sun — bronze-leaved cultivars tolerate full sun better','Tender annual: plant out only after frost danger passes and soil reaches at least 15-16 C (60 F); cold soil causes stunting','Toxic to cats and dogs']::text[], 0.6, '[{"citation":"North Carolina State Extension Gardener Plant Toolbox — Begonia, Wax Types: full sun (6+ h) to deep shade (<2 h) tolerated, bronze-leaved best in sun; mounded fibrous-rooted habit 6-12 in; hardy zones 9-11; tolerant of hot summers and mild drought; mealybugs, thrips, rot, fungal diseases; excellent in containers and hanging baskets","url":"https://plants.ces.ncsu.edu/plants/begonia-wax-types/","field":"lightProfile"},{"citation":"University of Minnesota Extension — Begonia: prefer shade, morning sun only; ~1 inch of water per week, let soil dry slightly, highly susceptible to root rot; fertilize monthly with higher-phosphorus bloom formula after balanced fertilizer at planting; transplant out once soil reaches 60 F; toxic to cats and dogs","url":"https://extension.umn.edu/flowers/begonia","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Begonia: fertilize monthly after planting with formula higher in phosphorus than nitrogen to promote blooms; balanced NPK worked in at planting","url":"https://extension.umn.edu/flowers/begonia","field":"feedingProfile"},{"citation":"Clemson University HGIC — Begonia factsheet: green-leaved cultivars best in morning sun/afternoon shade, bronze-leaved take full sun; keep soil moist but well drained; not heavy feeders (slow-release annual fertilizer); plant after frost danger; pests include spider mites, mealybugs, thrips, slugs; diseases include Botrytis, stem rot, powdery mildew","url":"https://hgic.clemson.edu/factsheet/begonia/","field":"temperatureProfile"},{"citation":"RHS — Begonias Outdoors (Summer Colour): sun or partial shade; water regularly in dry periods, avoid wetting foliage; feed weekly with high-potassium feed in containers through September; tender — plant out after frost danger; semperflorens potted on into 13 cm (5 in) pots","url":"https://www.rhs.org.uk/plants/begonias/outdoors","field":"containerProfile"},{"citation":"Illinois Extension — Wax Begonia, Fibrous Begonia: tender annual, wait for warm soil and air (cold soil stunts); full sun to shade once established with moisture; 6-12 in mature height; constant bloom May through October; moist, well-drained, high-organic-matter soil","url":"https://extension.illinois.edu/flowers/wax-begonia-fibrous-begonia","field":"seasonality"},{"citation":"Confidence note: baseIntervalDays=3 is derived from UMN''s ~1 inch/week with soil allowed to dry slightly, tightened for containers; hotWeatherMultiplier and rainSkipThresholdMm are conservative planner estimates, not stated by any source","field":"confidence"},{"citation":"Confidence note: recommendedMinLiters=2 converts RHS''s final 13 cm (5 in) pot per plant (~1 L) upward to a conservative single-plant container; ideal 3-10 L for fuller plants/mixed containers is an estimate. heatStressC=35 estimated from NCSU ''tolerant of hot summer temperatures'' plus RHS note of foliage scorch in intense heat","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('chlorophytum-comosum', 'Chlorophytum comosum', array['Spider plant','Airplane plant','Ribbon plant','Spider ivy']::text[], 'houseplant', 'rosette', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"medium","hotWeatherMultiplier":0.75}'::jsonb, '{"baseIntervalDays":90,"containerLeachAdjustment":1,"preferredNpk":"balanced water-soluble houseplant fertilizer (e.g. 10-10-10), standard strength every 3-4 months or half strength more often"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":8,"soilMixTags":["general-purpose-potting-mix","well-draining"]}'::jsonb, '{"targetSunHours":6,"minSunHours":3,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":7,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[3,4,5,6,7,8,9],"dormancyMonths":[11,12,1]}'::jsonb, array['Brown leaf tips from low humidity, dry soil, fertilizer/salt buildup, or fluoride and chlorine in tap water; use distilled or rain water if tips brown.','Root rot from overwatering or poorly draining soil; let the top of the soil dry slightly between thorough waterings.','Over-fertilizing reduces plantlet (''spiderette'') formation and can scorch leaf tips.','Direct midday sun can scorch leaves; prefers bright, indirect light.','Occasional pests: spider mites, scale, mealybugs, whiteflies, aphids.','Fleshy tuberous roots fill pots quickly; divide and repot before roots crack the container. Grows and produces plantlets best when slightly pot-bound, so the small recommended pot size is intentional.']::text[], 0.9, '[{"citation":"Clemson Cooperative Extension Home & Garden Information Center, ''Spider Plant (Chlorophytum comosum)'' — bright indirect light, tolerates some direct light (avoid midday sun); allow soil to dry slightly between waterings; day 65-75F (18-24C), night 50-55F (10-13C); fertilize during active growth; excellent hanging baskets; tip burn from salts/fluoride/low humidity; root rot from overwatering.","url":"https://hgic.clemson.edu/factsheet/spider-plant/","field":"wateringProfile"},{"citation":"Clemson HGIC spider plant factsheet — light and temperature guidance (bright indirect light; 65-75F day / 50-55F night ideal).","url":"https://hgic.clemson.edu/factsheet/spider-plant/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Chlorophytum comosum — USDA zones 9-11; keep above 45F (~7C) minimum; 55-70F preferred; medium water, keep moderately moist in active growth; avoid over-fertilizing (reduces plantlets); excellent for hanging baskets; tip browning from fluoride/salts; tolerates artificial light.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b547","field":"temperatureProfile"},{"citation":"University of Wisconsin-Madison Extension Horticulture, ''Spider plant, Chlorophytum comosum'' — fertilize every 3-4 months at standard strength (or half strength more often); allow soil to dry slightly between thorough waterings; fleshy water-storing roots tolerate inconsistent watering; grows best slightly pot-bound; medium to bright light indoors.","url":"https://hort.extension.wisc.edu/articles/spider-plant-chlorophytum-comosum/","field":"feedingProfile"},{"citation":"UW-Madison Extension spider plant article — pot-bound preference and rapid root growth used to set small container sizes; trailing plantlet stems make hanging baskets ideal (verticalSuitability).","url":"https://hort.extension.wisc.edu/articles/spider-plant-chlorophytum-comosum/","field":"containerProfile"},{"citation":"Confidence note: sources give qualitative guidance (''dry slightly between waterings'', ''bright indirect light'', no pot volumes). baseIntervalDays=7, targetSunHours=6 (bright indirect, hours of bright light not direct sun), container liters (2-8 L ~ 6-10 inch pot/basket), heatStressC=32, hotWeatherMultiplier=0.75, and seasonality months (plantlets form under fall short days; growth slows in winter) are conservative estimates derived from those qualitative statements, not explicit numbers in the cited pages.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('cosmos-bipinnatus', 'Cosmos bipinnatus', array['Cosmos','Garden Cosmos','Mexican Aster','Cut Leaf Cosmos','Cosmea']::text[], 'ornamental', 'bush', true, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high"}'::jsonb, '{"baseIntervalDays":90,"preferredNpk":"none / low-nitrogen only"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":15,"soilMixTags":["well-drained","low-fertility","neutral-to-alkaline-ph"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6}'::jsonb, '{"coldHardyMinC":1,"frostSensitive":true}'::jsonb, '{"productiveMonths":[7,8,9,10]}'::jsonb, array['Rich/over-fertilized soil produces leggy, weak-stemmed plants with abundant foliage but few flowers; do not fertilize and use lean soil (USU Extension).','Overwatering reduces blooming; let soil dry between waterings (USU Extension).','Taller cultivars (up to 1.5-2.5 m) flop and need staking or cane-and-twine support; dwarf cultivars usually do not (RHS).','Powdery mildew, stem canker, gray mold and southern blight can occur, especially in crowded or sheltered plantings; ensure free air movement (NC State Extension, RHS).','Container note: extension sources do not specify a pot volume. ~11 L (3 gal) suits dwarf/medium cultivars; tall 2+ m cultivars need a larger, well-anchored container and staking.']::text[], 0.1, '[{"citation":"RHS — Cosmos bipinnatus (cosmea). Full sun; moderately fertile, moist but well-drained soil; ultimate height 1.5-2.5 m; H3 hardiness (-5 to 1 C); flowers late summer into autumn until frost; taller cultivars need cane-and-twine support; mildew a risk without free air movement.","url":"https://www.rhs.org.uk/plants/30717/cosmos-bipinnatus/details","field":"lightProfile,temperatureProfile,requiresSupport,seasonality,commonIssues"},{"citation":"Utah State University Extension — Cosmos in the Garden. Full sun, at least 8 hours of light; water deeply about once weekly once established and thrives in drier soil (blooming reduced if overwatered); do NOT fertilize (rich soil yields weak-stemmed, late, sparse-flowering plants); neutral to slightly alkaline pH; germinates best 70-75 F (21-24 C); spacing 1-2 ft.","url":"https://extension.usu.edu/yardandgarden/research/cosmos-in-the-garden","field":"lightProfile,wateringProfile,feedingProfile,containerProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Cosmos bipinnatus. Full sun (6+ hours) to partial shade; well-drained clay/loam/sand, neutral-to-alkaline pH; drought tolerant, minimal water once established; annual, sow after frost when soil >=65 F (18 C); height 2-4 ft; suitable for containers; diseases include powdery mildew, stem canker, gray mold, southern blight; pests include aphids and aster leafhopper.","url":"https://plants.ces.ncsu.edu/plants/cosmos-bipinnatus/","field":"lightProfile,wateringProfile,temperatureProfile,containerProfile,commonIssues"},{"citation":"Confidence note: No extension/RHS source specifies a container volume for Cosmos bipinnatus, nor an explicit feeding interval (sources advise NO fertilizer). recommendedMinLiters (11), idealMinLiters (15) and feedingProfile.baseIntervalDays (90, i.e. effectively none) are conservative estimates derived from the plant''s 2-4 ft size, 1-2 ft spacing and lean-soil preference. coldHardyMinC (1 C) is taken from RHS H3 rating; the plant is a frost-sensitive annual regardless.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('dahlia-pinnata', 'Dahlia pinnata', array['Dahlia','Garden dahlia']::text[], 'ornamental', 'upright', true, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"high","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":28,"containerLeachAdjustment":0.5,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":30,"idealMinLiters":45,"idealMaxLiters":60,"soilMixTags":["rich","well-draining","loam","slightly-acidic"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6}'::jsonb, '{"coldHardyMinC":5,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"6":[{"startMonth":5,"endMonth":6}],"7":[{"startMonth":4,"endMonth":5}],"8":[{"startMonth":4,"endMonth":5}],"9":[{"startMonth":3,"endMonth":5}]},"productiveMonths":[7,8,9,10],"dormancyMonths":[11,12,1,2,3]}'::jsonb, array['Frost-tender: foliage is killed by first frost; in zones colder than 7, lift tubers after frost and store at roughly 0-10 C in slightly damp peat or sand','Tuber rot in cold, wet, or poorly drained soil — avoid overwatering before sprouts emerge','Powdery mildew on foliage; water the soil at the base, not the leaves','Slugs and snails on young shoots; aphids, spider mites, earwigs, caterpillars, and leafhoppers','Viruses and crown gall (discard infected plants)','Tall varieties topple without staking — set stakes at planting time to avoid injuring tubers later','High-nitrogen fertilizer produces leaves at the expense of blooms — use low-nitrogen feed such as 5-10-10','Container plants dry out much faster than in-ground plants and need more frequent watering and feeding']::text[], 0.1, '[{"citation":"Royal Horticultural Society — How to grow dahlias (RHS Growing Guide): warm sheltered sunny spot; regular watering of containers through the season; potassium-rich liquid feed fortnightly early July to early September in pots; ~50 cm wide container for one standard dahlia; keep indoors until temperatures are consistently above 5 C; stake standard and giant types; flowers summer to first frosts; lift and store tubers frost-free by late November; pests include slugs, snails, aphids, earwigs, capsid bugs, powdery mildew, viruses","url":"https://www.rhs.org.uk/plants/dahlia/growing-guide","field":"wateringProfile"},{"citation":"RHS Growing Guide — fortnightly potassium-rich (tomato-type) liquid feed for container dahlias July-September; 50 cm (20 in) wide pot for one standard dahlia","url":"https://www.rhs.org.uk/plants/dahlia/growing-guide","field":"containerProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Dahlia (group), Kemper Code a445: winter-hardy USDA zones 7-10; full sun, light filtered shade tolerated in hot summer climates; medium, consistent moisture in organically rich well-drained soil; blooms July-September; lift tuberous roots after first frost and store cool in damp peat; problems include viruses, crown gall, root rot, wilts, powdery mildew, aphids, caterpillars, spider mites, leafhoppers; smaller varieties do well in containers","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a445","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Dahlia (group): bloom July through September; plant tubers in spring; full sun","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a445","field":"seasonality"},{"citation":"Penn State Extension — The Dirt on Dahlias: heavy feeders, monthly low-nitrogen fertilizer such as 5-10-10 or 5-20-20; full sun; keep soil moist but not saturated; killed by frost; store tubers at 32-50 F (0-10 C); stake taller varieties; blooms mid-summer to first frost","url":"https://extension.psu.edu/the-dirt-on-dahlias","field":"feedingProfile"},{"citation":"Utah State University Extension — Growing Dahlias (fact sheet PDF): select a site with at least 6 hours of sun a day; water often enough to prevent the soil from drying out, soaking soil at the base rather than wetting foliage to prevent mildew; top-dress with 5-10-10 after sprouts emerge; plant after danger of spring frost; stake all but dwarf varieties at planting time; blooms July until killed by autumn frost","url":"https://extension.usu.edu/yardandgarden/files/Dahlias.pdf","field":"lightProfile"},{"citation":"Confidence note: sources specify ''water often enough to keep soil moist, never dry'' rather than an exact interval; baseIntervalDays=3 (about twice weekly, shortened by hotWeatherMultiplier in heat) is a conservative interpretation of USU/RHS/MOBOT guidance for an actively growing dahlia","field":"confidence"},{"citation":"Confidence note: container liters converted from RHS ''50 cm wide pot per standard dahlia'' (~45-55 L); recommendedMinLiters=30 reflects compact/bedding varieties RHS rates suitable for pots — exact liter figures are estimates, not published values","field":"confidence"},{"citation":"Confidence note: heatStressC=35 is an estimate derived from Missouri Botanical Garden''s advice that dahlias appreciate light filtered shade in hot summer climates; no source publishes an exact heat-stress threshold. Planting windows by zone are derived from ''plant after last spring frost'' (MOBOT/Penn State/USU) mapped to typical zone frost dates","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('dracaena-trifasciata', 'Dracaena trifasciata', array['Snake plant','Mother-in-law''s tongue','Sansevieria','Good luck plant','Saint George''s sword']::text[], 'houseplant', 'upright', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.8}'::jsonb, '{"baseIntervalDays":30,"preferredNpk":"balanced liquid houseplant or cactus fertilizer (e.g. dilute 10-10-10) monthly during spring-summer growing season only; do not feed in winter; heavy fertilization burns leaf margins"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":12,"soilMixTags":["well-drained","cactus-succulent-mix","gritty","peat-free-ok","snug-pot-preferred"]}'::jsonb, '{"targetSunHours":4,"minSunHours":1,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot from overwatering is by far the most common problem — let the potting mix dry out completely between waterings and never leave the pot standing in water','Reduce watering significantly from fall to late winter (roughly monthly) while the plant is not actively growing','Avoid pouring water directly into the center of the leaf rosette — it can rot the crown','Toxic if ingested (saponins): vomiting, nausea, diarrhea in pets and humans; sap may irritate skin','Pests: mealybugs, spider mites, scale, thrips, vine weevil','Tall narrow habit can make the plant top-heavy — use a wide, heavy (e.g. clay/terracotta) pot for stability','Tender tropical (USDA zones 10-12): keep above ~10 C, protect from frost and cold drafts; grow as an indoor/container plant outside those zones']::text[], 0.2, '[{"citation":"Missouri Botanical Garden Plant Finder — Dracaena trifasciata: zones 10-12; well-draining potting mix; water regularly in the growing season with significantly reduced watering from fall to late winter; avoid pouring water on the rosette center; prefers warm bright locations but tolerates some shade, protect from hot afternoon sun; overwatering causes root rot; mealybugs and spider mites; wide clay pots used so the tall narrow plant does not topple; height 2-4 ft","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b617","field":"wateringProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox — Dracaena trifasciata: partial shade (direct sun only part of the day, 2-6 hours) with tolerance for very low light; zones 10a-12b; tolerates cool temperatures around 50 F (10 C); erect clumping broadleaf evergreen; allow soil to dry between waterings spring-autumn, water only monthly in winter; toxic if ingested (saponins); mealybugs, spider mites, scale, thrips","url":"https://plants.ces.ncsu.edu/plants/dracaena-trifasciata/","field":"lightProfile"},{"citation":"RHS — How to grow sansevierias (Growing Guide): water only after the compost has completely dried out, barely any water in winter; feed once a month April-September with liquid houseplant or cactus feed; ideal 15-24 C, keep warm in winter and avoid cold drafts; snug pots preferred, repot only when roots fill the container, into a pot only slightly larger; free-draining peat-free cactus compost or loam-based compost with one part grit; overwatering/root rot is the most damaging mistake; mealybugs, red spider mite, vine weevil","url":"https://www.rhs.org.uk/plants/sansevieria/growing-guide","field":"feedingProfile"},{"citation":"Clemson University HGIC — Dracaena factsheet (covers snake plant within Dracaena): feed with liquid foliage plant fertilizer once a month during spring and summer; heavy fertilization burns leaf margins; allow soil to dry between waterings then water thoroughly; normal house temperatures 60-70 F; overwatering causes root rot; scale and mites","url":"https://hgic.clemson.edu/factsheet/dracaena/","field":"feedingProfile"},{"citation":"RHS — How to grow sansevierias: snug container preference and repot-only-when-rootbound guidance back the small recommended container size","url":"https://www.rhs.org.uk/plants/sansevieria/growing-guide","field":"containerProfile"},{"citation":"North Carolina State Extension + RHS — temperature bounds: NCSU ''tolerates cool temperatures around 50 F'' sets coldHardyMinC=10; RHS ideal range 15-24 C; frost kills the plant outdoors below zone 10","url":"https://plants.ces.ncsu.edu/plants/dracaena-trifasciata/","field":"temperatureProfile"},{"citation":"Confidence note: baseIntervalDays=14 is a planner-derived growing-season interval from ''water only after the compost has completely dried out'' (RHS) and ''allow soil to dry between waterings'' (NCSU/MoBot) — no source states an exact day count; winter watering should stretch to ~30 days (dormancyMonths). hotWeatherMultiplier=0.8 is a conservative planner estimate","field":"confidence"},{"citation":"Confidence note: recommendedMinLiters=2 (~15 cm pot) and ideal 3-12 L are planner estimates from RHS snug-pot guidance and MoBot''s wide-stable-pot note plus typical 2-4 ft mature size — no source states liters. heatStressC=35 is a conservative estimate; sources only give the 15-24 C ideal range. lightProfile hours map NCSU''s ''partial shade, 2-6 hours direct sun'' to target 4 / max 6; minSunHours=1 reflects documented tolerance of very low indoor light","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('epipremnum-aureum', 'Epipremnum aureum', array['Pothos','Golden Pothos','Devil''s Ivy','Hunter''s Robe']::text[], 'houseplant', 'vine', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.75,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":60,"containerLeachAdjustment":1,"preferredNpk":"balanced (e.g. 20-20-20) houseplant fertilizer"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":8,"soilMixTags":["well-draining","airy","soilless-potting-mix","peaty"]}'::jsonb, '{"targetSunHours":6,"minSunHours":2,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":10,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot from overwatering — better kept too dry than too wet (Penn State); brown or nonexistent roots indicate excess moisture','Yellowing or pale/scorched leaves from too much direct sun; grow in bright indirect or filtered light','Loss of variegation in low light (variegated cultivars)','Mealybugs, scale insects, and spider mites; treat with insecticidal soap','Leaf tip/margin blackening from over- or underwatering or excess fertilizer','All parts mildly toxic if ingested (calcium oxalate) — keep away from children and pets','Light values represent bright indirect light, not direct sun; avoid prolonged direct sunlight','Provide a moss pole or trellis if larger climbing foliage is desired; otherwise trails well from hanging baskets']::text[], 1, '[{"citation":"Clemson Cooperative Extension HGIC, ''How to Grow Pothos Indoors (Epipremnum spp.)'': allow soil to dry completely before watering; airy, well-draining soil mix; root rot from overwatering","url":"https://hgic.clemson.edu/factsheet/how-to-grow-pothos-indoors-epipremnum-spp-care-cultivars-and-common-problems/","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension HGIC: temperatures 60-70F nights and 70-85F days (15.5-29.5C); avoid AC/heat vents and cold windowsills","url":"https://hgic.clemson.edu/factsheet/how-to-grow-pothos-indoors-epipremnum-spp-care-cultivars-and-common-problems/","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC: fertilize with houseplant fertilizer every other month (~60 days) during spring and summer; bright indirect light, tolerates low light","url":"https://hgic.clemson.edu/factsheet/how-to-grow-pothos-indoors-epipremnum-spp-care-cultivars-and-common-problems/","field":"feedingProfile"},{"citation":"University of Wisconsin-Madison Horticulture Extension, ''Pothos, Epipremnum aureum'': filtered light, does not tolerate much direct sunlight; 70-90F (heat stress used ~32C); fertilize every other month except winter; hardy only in zones 10-12","url":"https://hort.extension.wisc.edu/articles/pothos-epipremmum-aureum/","field":"lightProfile"},{"citation":"Penn State Extension, ''Pothos as a Houseplant'': water when soil is dry, better kept too dry than too wet; 60-80F range; well-draining soilless potting mix; all parts poisonous (non-lethal) to humans and pets","url":"https://extension.psu.edu/pothos-as-a-houseplant","field":"wateringProfile"},{"citation":"South Dakota State University Extension, ''Pothos (Devil''s Ivy): House Plant How-To'': tolerates down to ~50F (10C); bright indirect light, low-light areas do fine; bi-monthly balanced fertilizer, none in winter dormancy","url":"https://extension.sdstate.edu/pothos-devils-ivy-golden-pothos-house-plant-how","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Epipremnum aureum ''Neon'': zones 10-12, part shade / bright indirect light, medium water; peaty potting mix; roots may rot in poorly drained soils; scale, mealybugs, mites; stems to 20 ft","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=369734","field":"containerProfile"},{"citation":"Confidence note: sources say ''water when soil is dry'' without a fixed interval — 7 days is a conservative indoor estimate. No extension source specifies pot volume — 2 L minimum (~15 cm / 6-inch pot) is an estimate from standard houseplant practice and MoBot repotting guidance. Light hours are an indoor bright-indirect equivalent, not measured direct-sun hours; extensions describe light qualitatively (bright indirect, tolerates low light).","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('ficus-elastica', 'Ficus elastica', array['Rubber plant','Rubber tree','India rubber fig','India rubber tree']::text[], 'houseplant', 'tree', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.75,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.9,"preferredNpk":"high-nitrogen balanced houseplant fertilizer (e.g. 24-8-16 or 10-10-10), spring through summer only"}'::jsonb, '{"recommendedMinLiters":10,"idealMinLiters":15,"idealMaxLiters":50,"soilMixTags":["well-drained","houseplant-mix","loam-based","soil-based-potting-mix"]}'::jsonb, '{"targetSunHours":6,"minSunHours":3,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":10,"heatStressC":30,"frostSensitive":true}'::jsonb, '{"productiveMonths":[3,4,5,6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot and leaf yellowing from overwatering or poor drainage — let soil dry slightly between waterings and never leave the pot standing in water','Sudden leaf drop from cold drafts, low light, overwatering, or temperatures below about 10-13 C','Pests: scale, mealybugs, aphids, thrips, and spider mites','Milky latex sap can irritate skin and is mildly toxic if ingested — keep away from pets and children, wash hands after pruning','In the wild this is a 15-30 m tree (hardy only in USDA zones 10-12); grown as a 1-3 m container houseplant elsewhere — the 10 L container minimum is for a young indoor plant, size up every 2-3 years as it grows','Reduce watering from fall to late winter; resume regular watering and feeding in spring']::text[], 0.05, '[{"citation":"Clemson University Home & Garden Information Center, ''Rubber Plant'' factsheet — water thoroughly, let soil dry slightly between waterings; ensure drainage; root rot/yellowing from excess moisture","url":"https://hgic.clemson.edu/factsheet/rubber-plant/","field":"wateringProfile"},{"citation":"Clemson HGIC ''Rubber Plant'' — ideal temperatures 75-80 F (24-27 C) day, 60-65 F (16-18 C) night; avoid below 55 F (13 C), sudden drops, and cold drafts","url":"https://hgic.clemson.edu/factsheet/rubber-plant/","field":"temperatureProfile"},{"citation":"Clemson HGIC ''Rubber Plant'' — prefers bright light, adaptable to low light, grows best with morning light from an east window; fertilize every two weeks with water-soluble houseplant fertilizer during spring/summer active growth","url":"https://hgic.clemson.edu/factsheet/rubber-plant/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Ficus elastica — USDA zones 10-12; 50-100 ft in habitat, 2-10 ft as houseplant; part shade / bright indirect light; medium water, water regularly in growing season, reduce fall to late winter; soil-based potting mix; pests: scale, aphids, mealybugs, thrips, spider mites","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b597","field":"seasonality"},{"citation":"RHS, Ficus elastica (rubber plant) plant profile — hardiness H1b (grow outside only in summer, 10-15 C minimum); bright but filtered/indirect light; water moderately in growth, sparingly in winter; high-nitrogen fertiliser monthly; repot every 2-3 years","url":"https://www.rhs.org.uk/plants/95720/ficus-elastica/details","field":"feedingProfile"},{"citation":"RHS Growing Guide, ''How to grow ornamental figs'' — keep above 10-13 C (50-55 F); bright indirect light, tolerates a few hours of morning/evening sun; let compost dry slightly between waterings; loam-based compost (John Innes No 3) with fine bark; move to a slightly larger container every couple of years","url":"https://www.rhs.org.uk/plants/ornamental-figs/growing-guide","field":"containerProfile"},{"citation":"Confidence note: sources give qualitative watering guidance (''let soil dry slightly between waterings'', ''water moderately'') with no day interval; 7 days is a conservative indoor estimate derived from that guidance. Light is specified as ''bright indirect'' rather than sun-hours; 6 h target / 3-8 h range is an estimate mapping ''bright light, adaptable to low light, some morning sun''. No authoritative source states a pot volume; 10 L minimum (≈25 cm pot) is an estimate consistent with RHS ''slightly larger container every couple of years'' repotting practice. heatStressC 30 is an estimate above the Clemson 24-27 C ideal day range.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('helianthus-annuus', 'Helianthus annuus', array['Sunflower','Common sunflower','Annual sunflower']::text[], 'ornamental', 'upright', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":2,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"containerLeachAdjustment":0.5,"preferredNpk":"balanced low-nitrogen (e.g. 10-10-10), worked in at planting; avoid high-nitrogen feeds that promote leaves over flowers. RHS option: potassium-rich tomato-type feed once flower buds form."}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-draining","rich-in-organic-matter","slightly-acidic-to-neutral-pH-6.0-7.5"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"default":[{"startMonth":4,"endMonth":6}],"south-us":[{"startMonth":3,"endMonth":4}]},"productiveMonths":[7,8,9,10],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Direct-sow only after the last spring frost once soil has warmed to at least 10C (50F); seedlings and plants are frost-sensitive. Sunflowers dislike root disturbance, so direct sowing is preferred over transplanting.','Container plants dry out fast and need watering more frequently than in-ground plantings, potentially daily in hot weather; check the top 5cm (2in) of soil and water when dry. Established in-ground plants are drought-tolerant and need deep watering roughly weekly with several gallons, especially 20 days before and after flowering.','recommendedMinLiters (19 L, a 5-gallon bucket) targets dwarf/container cultivars of max ~1m (3ft). Tall and giant cultivars (2-5m+) are really in-ground plants; an undersized container restricts roots, stunts growth and makes them top-heavy and prone to lodging (falling over).','Tall and giant cultivars (over ~2.4m / 8ft) typically need staking or a sturdy cane against wind and heavy seed heads; dwarf and semi-dwarf cultivars usually do not. Plant in a spot sheltered from strong winds.','Long taproot prefers a deep, loosened bed (dig/till ~60cm deep). Avoid high-nitrogen fertilizer, which encourages foliage over flowers and can weaken stems.','Generally low-maintenance; watch for slugs/snails on young plants, birds and squirrels on ripening seed heads, and occasional powdery/downy mildew or Sclerotinia rot in damp, crowded conditions.']::text[], 0.1, '[{"citation":"Clemson Cooperative Extension HGIC - Let''s Grow Sunflowers: locations receiving 6 to 8 hours of direct sunlight are preferable; well-draining soil with pH 6-7.5; sow once soils warm above 50F (10C) and frost danger passes; heavy feeders benefit from regular slow-release fertilizer; large plants may need support for wind and top-heaviness from seed production.","url":"https://hgic.clemson.edu/lets-grow-sunflowers/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC - Let''s Grow Sunflowers: seeds planted once soils warm above 50F (10C) and frost danger passes; frost-sensitive warm-season annual.","url":"https://hgic.clemson.edu/lets-grow-sunflowers/","field":"temperatureProfile"},{"citation":"RHS Growing Guide - Helianthus (sunflowers): full sun; annual sunflowers are thirsty plants needing consistently moist soil and mustn''t dry out; container plants need watering whenever the compost feels dry, potentially daily in hot weather; feed annuals with potassium-rich tomato fertiliser to encourage flowering.","url":"https://www.rhs.org.uk/plants/helianthus/growing-guide","field":"wateringProfile"},{"citation":"RHS Growing Guide - Helianthus (sunflowers): potassium-rich tomato fertiliser encourages flowering for annual types; sow indoors from late March, direct outdoors mid-April through May; transplant only once soil is warming and there is no frost risk after hardening off.","url":"https://www.rhs.org.uk/plants/helianthus/growing-guide","field":"feedingProfile"},{"citation":"RHS Growing Guide - Helianthus (sunflowers): annual sunflowers cannot tolerate frost; most annuals need sturdy bamboo cane support and giant cultivars over 2.4m (8ft) need extra securing (e.g. against a wall); dwarf types are ~30cm (1ft) tall.","url":"https://www.rhs.org.uk/plants/helianthus/growing-guide","field":"requiresSupport"},{"citation":"University of Minnesota Extension - Sunflowers: enjoy full sun; do best in slightly acidic soil pH 6.0-6.8, well-drained; direct seed after all danger of frost passes; can withstand some drought but water regularly 20 days before and after flowering; side dressing of all-purpose slow-release fertilizer when plants have several true leaves; giant (8ft+) cultivars sometimes require staking.","url":"https://extension.umn.edu/flowers/sunflowers","field":"wateringProfile"},{"citation":"University of Minnesota Extension - Sunflowers: full sun; seeds germinate in 7-10 days; spacing 6in (2-5ft varieties) up to 2ft (giant cultivars); soil test recommended before planting.","url":"https://extension.umn.edu/flowers/sunflowers","field":"seasonality"},{"citation":"Oregon State University Extension EM 9866 ''Grow your own sunflowers'': for containers choose dwarf cultivars max 3ft tall (less likely to become top-heavy); use a large container - a 5-gallon bucket (~19 L) with drainage holes or similar provides enough root space; well-draining potting mix; irrigate containers more frequently than in-ground; full sun 6-8+ hours; well-drained soil pH 6.0-7.5.","url":"https://extension.oregonstate.edu/catalog/em-9866-grow-your-own-sunflowers","field":"containerProfile"},{"citation":"Oregon State University Extension EM 9866 ''Grow your own sunflowers'': use a balanced fertilizer (e.g. NPK 10-10-10) and avoid high-nitrogen fertilizers that promote leaf growth over flower formation; slow-release or split quick-release (half at planting, half at two sets of leaves); direct sow April-June after last frost when soil reaches at least 50F (10C); high winds can topple tall cultivars and staking helps.","url":"https://extension.oregonstate.edu/catalog/em-9866-grow-your-own-sunflowers","field":"feedingProfile"},{"citation":"Old Farmer''s Almanac - Sunflowers: sow directly after danger of spring frost passes, once soils warm to at least 50F (10C); northern US/Canada April to mid-June, South mid-March or early April; full sun 6-8 hours; thrive in slightly acidic to alkaline soil pH 6.0-7.5; once established water deeply but infrequently, about once a week with several gallons; tall species and cultivars require support (bamboo stakes); feed sparingly to avoid weak stems.","url":"https://www.almanac.com/plant/sunflowers","field":"seasonality"},{"citation":"Confidence note: wateringProfile.baseIntervalDays (3) is a conservative container-oriented estimate. Sources give qualitative watering guidance (RHS: water containers when compost dry, potentially daily in heat; UMN/Almanac: established in-ground deep watering ~weekly with several gallons) rather than a single fixed day interval; a 3-day base with a 2x hot-weather multiplier brackets both container and in-ground regimes. heatStressC (35C), maxSunHours (14) and rainSkipThresholdMm (10) are reasonable horticultural/care-engine estimates, not directly cited figures.","field":"confidence"},{"citation":"Confidence note: container volumes (recommendedMinLiters 19 = a 5-gallon bucket per OSU Extension, ideal 19-38 L) target dwarf/container cultivars (max ~3ft). Tall and giant cultivars are effectively in-ground plants and any single container minimum is an approximation; idealMaxLiters (38 L) is an estimate scaled for larger semi-dwarf types (see commonIssues).","field":"containerProfile"}]'::jsonb, 1, '2026-06-02'),
  ('impatiens-walleriana', 'Impatiens walleriana', array['Impatiens','Busy Lizzie','Bizzy Lizzy','Common Impatiens','Garden Impatiens','Patience Plant','Sultana']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"high","hotWeatherMultiplier":0.5}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.5,"preferredNpk":"low-nitrogen, higher-phosphorus (e.g. 5-10-5) to favor blooms over foliage"}'::jsonb, '{"recommendedMinLiters":3,"idealMinLiters":4,"idealMaxLiters":10,"soilMixTags":["soilless-mix","well-drained","organic-rich","slightly-acidic"]}'::jsonb, '{"targetSunHours":3,"minSunHours":0,"maxSunHours":4}'::jsonb, '{"coldHardyMinC":5,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Very susceptible to impatiens downy mildew (Plasmopara obducens); there is no cure once established, so remove and discard infected plants and choose resistant cultivars (UMN, Clemson, NC State).','Wilts quickly in hot, dry weather and in containers; needs extra water during heat. Container plants and hanging baskets may need daily watering (UMN, Clemson).','Overwatering or waterlogged soil causes rot, damping-off, and root disease; ensure drainage holes (UMN, Clemson).','Very cold sensitive; do not plant outdoors until soil reaches ~60 degrees F (~15.6 C) and all frost danger has passed (UMN, Clemson).','Becomes leggy by late summer; pinch or trim back the top one-third to encourage new blooms (Old Farmer''s Almanac).','Container minimum liters are an app estimate: extension sources specify pot/hanging-basket use with good drainage but not a liter volume.']::text[], 0.7, '[{"citation":"University of Minnesota Extension — Impatiens. Best in part to full shade; sites with 2-4 hours filtered sun or morning sun/afternoon shade are ideal; too much sun scorches leaves.","url":"https://extension.umn.edu/flowers/impatiens","field":"lightProfile"},{"citation":"University of Minnesota Extension — Impatiens. Walleriana cultivars grown in shade; very sensitive to cold, do not plant until soil is 60 F (15.6 C) or warmer.","url":"https://extension.umn.edu/flowers/impatiens","field":"temperatureProfile"},{"citation":"University of Minnesota Extension — Impatiens. In garden beds water only when the top 1-2 inches of soil is dry; container plants need daily watering with drainage holes; drooping leaves indicate insufficient moisture.","url":"https://extension.umn.edu/flowers/impatiens","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Impatiens. Apply balanced granular fertilizer at planting, then fertilize monthly with a product higher in phosphorus than nitrogen to promote flowers over foliage.","url":"https://extension.umn.edu/flowers/impatiens","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Impatiens. Very susceptible to downy mildew; remove heavily infected plants; no cure once established.","url":"https://extension.umn.edu/flowers/impatiens","field":"commonIssues"},{"citation":"Clemson Cooperative Extension HGIC — Impatiens. Older types thrive in filtered/partial shade and must be protected from hot afternoon sun; require rich, moist, mulched soil kept consistently moist but not waterlogged; avoid overhead watering.","url":"https://hgic.clemson.edu/factsheet/impatiens/","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension HGIC — Impatiens. Fertilize monthly with a water-soluble fertilizer; use a soilless growing mix with good drainage for containers, which need more frequent watering and feeding than garden plants.","url":"https://hgic.clemson.edu/factsheet/impatiens/","field":"containerProfile"},{"citation":"Clemson Cooperative Extension HGIC — Impatiens. Tender annuals; plant after the final frost date. Primary disease concern is downy mildew, plus damping-off, fungal blights, rots, and viruses.","url":"https://hgic.clemson.edu/factsheet/impatiens/","field":"temperatureProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Impatiens walleriana. Mounding/bushy tender annual (commonly 6-30 in tall), prized for shade beds, containers, and hanging baskets; requires moist, well-drained, organic-rich, slightly acidic soil.","url":"https://plants.ces.ncsu.edu/plants/impatiens-walleriana/","field":"containerProfile"},{"citation":"The Old Farmer''s Almanac — How to Grow Impatiens. By late summer plants get leggy; trim off the top one-third to promote new blooms and improve appearance.","url":"https://www.almanac.com/plant/impatiens","field":"commonIssues"},{"citation":"Confidence note: heatStressC (32 C) and coldHardyMinC (5 C) are conservative app estimates. Extension sources state impatiens wilt in hot, dry spells and are very cold-sensitive (plant only when soil >= 60 F / 15.6 C, after last frost) but do not publish exact threshold temperatures in Celsius. Container recommendedMinLiters (3 L) is also an estimate — sources confirm pot/basket suitability with good drainage but give no volume.","url":"https://extension.umn.edu/flowers/impatiens","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('lobularia-maritima', 'Lobularia maritima', array['Sweet alyssum','Alyssum','Sweet alison']::text[], 'ornamental', 'trailing', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":6}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"balanced all-purpose (e.g. 10-10-10), applied sparingly"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":4,"idealMaxLiters":10,"soilMixTags":["well-drained","light","moderately-fertile","tolerates-alkaline"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-5,"heatStressC":29,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":4,"endMonth":5}],"7":[{"startMonth":3,"endMonth":4}],"9":[{"startMonth":2,"endMonth":3},{"startMonth":9,"endMonth":10}]},"productiveMonths":[4,5,6,7,8,9,10]}'::jsonb, array['Flowering slows or stops in hot summer weather; plants look ragged but usually revive in cooler fall temperatures (shear to encourage rebloom)','Stems can rot in overly wet or crowded conditions; avoid overwatering and ensure good drainage','Damping off occasionally affects seedlings','Susceptible to downy mildew, clubroot, white blister, slugs, and flea beetles','Heavy fertilization promotes foliage at the expense of flowers; feed sparingly','Deadhead or clip over after the first flush of bloom to encourage further flowering']::text[], 0.8, '[{"citation":"University of Wisconsin-Madison Extension Horticulture, ''Sweet Alyssum, Lobularia maritima'' — full sun in cool climates, part shade in hot climates; tolerates short dry periods but best with consistent moisture; avoid overwatering (rot in wet/crowded conditions); fertilize sparingly; mat-forming 3-9 in. tall; ideal for containers and hanging baskets; flowering slows in heat and revives in fall.","url":"https://hort.extension.wisc.edu/articles/sweet-alyssum-lobularia-maritima/","field":"wateringProfile"},{"citation":"University of Wisconsin-Madison Extension Horticulture, ''Sweet Alyssum, Lobularia maritima'' — full sun (cool climates) to partial shade (hot climates); basis for 6 h target / 4 h minimum sun.","url":"https://hort.extension.wisc.edu/articles/sweet-alyssum-lobularia-maritima/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder, ''Lobularia maritima'' (Kemper Code a103) — full sun to part shade; water dry to medium, tolerates drought and dry soil; zones 5-9 (grown as annual); blooms spring to frost in cool-summer climates; declines in summer heat, revives in fall; 0.25-0.75 ft tall, 0.5-1 ft wide; suitable for mixed containers; no serious insect or disease problems.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a103","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, ''Lobularia maritima'' — dry-to-medium water needs and drought tolerance; basis for medium dryingTolerance.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a103","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension Home & Garden Information Center, ''Sweet Alyssum'' — sunny location with some afternoon shade; fertilize monthly with all-purpose fertilizer through the growing season (basis for 30-day feeding interval); excels in pots, hanging baskets and window boxes; plant several weeks before the last spring frost; September sowing flowers fall through winter in mild climates.","url":"https://hgic.clemson.edu/sweet-alyssum/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC, ''Sweet Alyssum'' — container, hanging-basket and window-box suitability; cascading habit over edges (basis for trailing growthHabit and verticalSuitability 0.8).","url":"https://hgic.clemson.edu/sweet-alyssum/","field":"containerProfile"},{"citation":"Royal Horticultural Society, ''Lobularia maritima'' — hardiness H3 (minimum -5 to 1 C; basis for coldHardyMinC -5); full sun; light, moderately fertile, well-drained soil, any pH; up to 10 cm tall, 10-50 cm spread; suitable for patios and containers; pests/diseases: downy mildew, clubroot, white blister, slugs, flea beetles; clip over after first flush to encourage further flowering.","url":"https://www.rhs.org.uk/plants/124133/lobularia-maritima/details","field":"temperatureProfile"},{"citation":"Royal Horticultural Society, ''Lobularia maritima'' — light, moderately fertile, well-drained soil across chalk/clay/loam/sand; basis for soilMixTags.","url":"https://www.rhs.org.uk/plants/124133/lobularia-maritima/details","field":"containerProfile"},{"citation":"Confidence note: sources give qualitative guidance (''consistent moisture'', ''dry to medium'', ''fertilize monthly'', ''declines in summer heat''). Numeric conversions are conservative estimates: baseIntervalDays 2 (container annual needing consistent moisture), hotWeatherMultiplier 0.5, rainSkipThresholdMm 6, container liters 2/4-10 (small shallow-rooted 8-23 cm plant; standard 15-25 cm pot or basket), heatStressC 29 (flowering decline reported in hot summers), maxSunHours 10. No source states these exact numbers.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('monstera-deliciosa', 'Monstera deliciosa', array['Monstera','Swiss Cheese Plant','Split-leaf Philodendron','Ceriman','Mexican Breadfruit']::text[], 'houseplant', 'climbing', true, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.8}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":1.0,"preferredNpk":"balanced 20-20-20 liquid at half strength (salt-sensitive)"}'::jsonb, '{"recommendedMinLiters":10,"idealMinLiters":10,"idealMaxLiters":40,"soilMixTags":["well-draining","high-organic-matter","peaty-soil-based","slightly-acidic-to-neutral","orchid-bark-amendment"]}'::jsonb, '{"targetSunHours":4,"minSunHours":2,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[4,5,6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root and stem rot from overwatering or pots standing in water (UConn, RHS); always let the upper soil dry before watering','Leaves fail to develop characteristic splits/holes (fenestration) in inadequate light (Wisconsin Horticulture, RHS)','Large leaves sunburn easily when moved into stronger direct sun (UConn)','Brown leaf edges from dry indoor air; prefers medium-to-high humidity (Wisconsin Horticulture, RHS)','Pests: mealybugs, spider mites, scale, aphids, thrips (Wisconsin Horticulture, Missouri Botanical Garden)','Salt burn: easily damaged by high soil salts, so fertilize at reduced strength (UConn)','All parts except fully ripe fruit contain calcium oxalate and are toxic to people and pets (Wisconsin Horticulture, NC State)','Grown indoors as a foliage plant; flowering and fruiting are rare in home environments (Missouri Botanical Garden, NC State)','Top-heavy vine: needs a moss pole, bark slab, or sturdy stake to prevent stem breakage (UConn, Wisconsin Horticulture, Missouri Botanical Garden)']::text[], 0.9, '[{"citation":"University of Connecticut Home & Garden Education Center, ''Monstera deliciosa'' factsheet — partial shade with 3-6 hours direct sun daily; allow top 2-3 inches of soil to dry between waterings; hardy zones 10a-12b, tolerates outdoor placement above 45F; fertilize during active growth (May-September), easily burned by high soil salts; well-draining mix with high organic matter; repot gradually, tolerates pot-bound better than over-potting; moss pole support","url":"https://homegarden.cahnr.uconn.edu/factsheets/monstera-deliciosa/","field":"lightProfile"},{"citation":"UConn Home & Garden Education Center — watering: allow top 2-3 in of soil to dry between waterings (roughly weekly indoors); susceptible to root disease in cool months, needs consistent drainage","url":"https://homegarden.cahnr.uconn.edu/factsheets/monstera-deliciosa/","field":"wateringProfile"},{"citation":"University of Wisconsin-Madison Extension, Wisconsin Horticulture, ''Swiss-Cheese Plant, Monstera deliciosa'' — does not grow below 50F (10C), frost kills; bright light in summer, direct sun in winter; water thoroughly and allow soil to dry slightly between waterings, less in winter; fertilize regularly spring to fall; needs ample root room and support (tree bark or moss-covered pole); pests: aphids, mealybugs, scale, spider mites","url":"https://hort.extension.wisc.edu/articles/monstera-deliciosa/","field":"temperatureProfile"},{"citation":"Royal Horticultural Society, ''How to grow Swiss cheese plants'' — keep at 18-25C year-round; indirect light by an east/west window; let compost nearly dry then water thoroughly, never leave standing in water; feed balanced liquid fertilizer April-September; repot into only slightly larger pots; mix of 1 part ericaceous peat-free compost to 2 parts orchid compost; train onto a moss pole","url":"https://www.rhs.org.uk/plants/swiss-cheese-plants/how-to-grow-swiss-cheese-plants","field":"feedingProfile"},{"citation":"Missouri Botanical Garden Plant Finder, ''Monstera deliciosa'' — USDA zones 10-12; bright indoor light, no strong direct sun; medium water, regular in growing season, reduced fall through late winter; peaty soil-based potting mix; 6-8 ft indoors (30-70 ft in habitat); needs pole/trellis support; indoor plants rarely flower and fruit; pests include aphids, mealybugs, thrips, scale, spider mites","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b605","field":"containerProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox, ''Monstera deliciosa'' — tolerates dappled sunlight or partial shade (2-6 hours direct sun); water thoroughly then allow top quarter-to-third of soil to dry; zones 10a-12b, houseplant elsewhere; climbing vine 6-8 ft indoors; rarely fruits indoors; toxic (calcium oxalate); medium maintenance, sturdy support required","url":"https://plants.ces.ncsu.edu/plants/monstera-deliciosa/","field":"lightProfile"},{"citation":"Confidence note: sources give watering as a soil-dryness test (top 2-3 in dry), not a fixed interval; 7-day base interval is a conservative indoor estimate. Container liters are estimated (10 L = ~25 cm pot for an established plant; sources advise gradual up-potting in only slightly larger pots, no explicit volumes). heatStressC 35C and hotWeatherMultiplier 0.8 are conservative estimates from the 18-29C preferred range; feeding interval 30 days estimated from ''fertilize regularly/monthly during the April-September growing season''.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('pelargonium-x-hortorum', 'Pelargonium x hortorum', array['Geranium','Zonal Geranium','Bedding Geranium','Garden Geranium']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":8}'::jsonb, '{"baseIntervalDays":28,"preferredNpk":"10-20-10"}'::jsonb, '{"recommendedMinLiters":3.8,"idealMinLiters":5,"idealMaxLiters":11,"soilMixTags":["well-drained","fertile","neutral-to-alkaline","peat-or-compost-amended"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":5,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Frost-tender (USDA zones 10-11); plant outdoors only after all frost danger passes and soil reaches about 16C (60F).','Overwatering and poorly drained soil cause stem and root rot and edema; let the top 2.5-5 cm (1-2 in) of soil dry before watering and never let pots sit in water.','Bacterial leaf spot, botrytis (gray mold) blight, and leaf spots; avoid overhead watering and wetting foliage.','Aphids, whiteflies, spider mites, caterpillars, and tobacco budworm.','Leggy growth and leaf drop indoors from insufficient light; bright south/west window or supplemental light needed.','Recommended container minimum is a single-plant pot (about 6-inch / 3.8 L); larger pots hold more water and reduce wilting, so size up if plants wilt frequently.']::text[], 0.3, '[{"citation":"Clemson Cooperative Extension HGIC, Annual Geranium (Pelargonium): at least 4 hours direct sun daily (midday shade in very hot areas); allow soil to dry between waterings; keep water off foliage; fertilize every 4 to 6 weeks during the growing season with 10-20-10 or equivalent; use large, well-drained containers; plant after frost danger and soil warming; problems include bacterial leaf spot, botrytis blight, edema, aphids, caterpillars, mites, whiteflies.","url":"https://hgic.clemson.edu/factsheet/geranium/","field":"lightProfile,wateringProfile,feedingProfile,temperatureProfile,commonIssues"},{"citation":"University of Minnesota Extension, Growing geraniums as annual flowers in Minnesota: minimum 8 hours sun (less sun = fewer flowers); water when top 1-2 inches of soil is dry; geraniums tolerate dry soil better than overly wet; fertilize roughly every 3 weeks at half strength with all-purpose water-soluble fertilizer; minimum 6-inch pot with drainage; plant outdoors when soil reaches 60F; dormant overwinter storage at 45-50F watering monthly.","url":"https://extension.umn.edu/flowers/growing-geraniums-minnesota","field":"lightProfile,wateringProfile,feedingProfile,containerProfile,temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Pelargonium x hortorum: USDA hardiness zones 10-11; full sun to part shade; medium water needs; height/spread 1-3 ft shrubby mounds; frost-tender; suitable for containers, hanging baskets and window boxes; poorly drained soils lead to stem and root rots; susceptible to leaf spots, gray mold, whiteflies, aphids, tobacco budworm.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a537","field":"category,growthHabit,containerProfile,temperatureProfile,commonIssues"},{"citation":"Royal Horticultural Society (RHS) Pelargonium Growing Guide: water moderately spring-summer and sparingly in winter, letting compost dry between waterings; feed every 10-14 days with balanced fertilizer then switch to high-potassium (tomato) feed once flowers form; minimum 7-10C and frost-free to overwinter; soil-based (John Innes No.2) or multipurpose compost; problems include grey mould, rust, whitefly, vine weevil.","url":"https://www.rhs.org.uk/plants/pelargonium/growing-guide","field":"feedingProfile,temperatureProfile"},{"citation":"Confidence note: heatStressC (32C) and coldHardyMinC (5C) are conservative estimates. Sources establish frost-tenderness and USDA zone 10-11 hardiness (Missouri Botanical Garden) and recommend midday shade in ''very hot areas'' (Clemson) but give no exact Celsius heat-stress or cold-survival thresholds; UMN cites 45-50F (7-10C) dormant storage and 60F (16C) planting soil. The container recommendedMinLiters (3.8 L / ~1 gal) is derived from UMN''s 6-inch minimum pot width converted to a realistic single-plant volume.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('petunia-x-hybrida', 'Petunia x hybrida', array['Petunia','Garden petunia','Hybrid petunia']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":1,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":14,"containerLeachAdjustment":0.5,"preferredNpk":"balanced (e.g. 10-10-10) or bloom-booster higher-phosphorus liquid feed; slow-release fertilizer mixed into the potting mix at planting"}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":11,"idealMaxLiters":20,"soilMixTags":["well-drained","quality-potting-mix","medium-fertility","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":8,"minSunHours":5}'::jsonb, '{"coldHardyMinC":0,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[5,6,7,8,9,10]}'::jsonb, array['Frost-tender annual in most climates (perennial only in USDA zones 10-11): plant out only after the last spring frost, once soil has warmed to about 15-16 C (60 F).','Too little sun makes plants spindly with few flowers; petunias need at least 5-6 hours of direct sun and bloom best in full sun all day.','Plants get leggy by midsummer; cut shoots back by about half, then feed and water to force fresh growth and bloom.','Deadhead spent flowers regularly (especially large-flowered types) to keep new buds forming.','Containers and hanging baskets dry out fast in summer and may need water daily, sometimes twice a day in heat; in-ground plants need far less (a deep weekly soak).','Avoid soggy soil and frequent shallow watering: poor drainage invites root rot and gray mold, and shallow watering encourages shallow roots.','Petal blight and fungal problems appear in rainy/very humid weather, especially on grandiflora types; avoid wetting the foliage.','Watch for aphids and slugs/snails; knock aphids off with water and handpick or trap slugs.','Spreading/trailing (e.g. Wave-type) petunias are heavier feeders and drinkers than standard types: feed weekly and water more often.']::text[], 0.85, '[{"citation":"University of Minnesota Extension, ''Growing petunias'': at least 5-6 hours of good sunlight, best in full sun all day; in-ground plants need a thorough weekly watering soaking soil 6-8 inches deep, while container plantings may need daily watering; garden beds get balanced fertilizer (8-8-8, 10-10-10, or 12-12-12) at planting then liquid feed every ~3 weeks from July; containers get timed-release fertilizer at planting then flowering-plant liquid feed every 2 weeks (weekly for spreading types); transplant after frost danger when soil is about 60 F; start seed indoors 10-12 weeks before planting out.","url":"https://extension.umn.edu/flowers/growing-petunias","field":"lightProfile"},{"citation":"University of Minnesota Extension, ''Growing petunias'': container petunias may need daily watering in summer depending on pot size and soil volume; in-ground plants need a thorough weekly soak 6-8 inches deep; spreading types need frequent watering.","url":"https://extension.umn.edu/flowers/growing-petunias","field":"wateringProfile"},{"citation":"University of Minnesota Extension, ''Growing petunias'': feed container petunias every 2 weeks with a flowering-plant liquid fertilizer (weekly for spreading types); timed-release fertilizer incorporated at planting; balanced 8-8-8 / 10-10-10 / 12-12-12 for beds.","url":"https://extension.umn.edu/flowers/growing-petunias","field":"feedingProfile"},{"citation":"Clemson University Home & Garden Information Center, ''Petunia'' (HGIC): full sunlight required, plants become spindly with few flowers in shade; 1-2 inches of water every 7-10 days once established in ground, avoid frequent light watering; fertilize monthly with a balanced fertilizer; well-drained light soil of medium fertility, pH 6.0-7.0; heights 6-18 in, spread 18 in to 4 ft; excellent for containers and hanging baskets; aphids, slugs, and petal blight in rainy/humid weather are the main problems.","url":"https://hgic.clemson.edu/factsheet/petunia/","field":"wateringProfile"},{"citation":"Clemson University HGIC ''Petunia'': soil pH 6.0-7.0, well-drained light soil of medium fertility; excellent for containers and hanging baskets.","url":"https://hgic.clemson.edu/factsheet/petunia/","field":"containerProfile"},{"citation":"The Old Farmer''s Almanac, ''Petunias: How to Plant, Grow, and Care for Petunias'': annual in most areas, tender perennial only in zones 9-11; plant out after last spring frost and protect young plants from late frosts; full sun or plants become spindly; thorough weekly watering suffices in ground, but spreading types and container plants need more frequent watering; fertilize monthly with balanced fertilizer (biweekly for double-flowered cultivars); prune leggy plants back by half in midsummer; aphids and slugs are the main pests; fungal disease develops with excess moisture and poor airflow.","url":"https://www.almanac.com/plant/petunias","field":"feedingProfile"},{"citation":"The Old Farmer''s Almanac, ''Petunias'': blooms from spring until frost; treated as annuals, tender perennial in zones 9-11; frost-sensitive — plant after last spring frost; height 6-18 in, spread 18 in to 4 ft; spreading/trailing types ideal for window boxes and hanging baskets.","url":"https://www.almanac.com/plant/petunias","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, ''Petunia (group)'': winter hardy USDA zones 10-11, grown as an annual elsewhere; full sun to part shade; medium water; height 0.75-1 ft, spread 1-3 ft; blooms May to frost; average, medium-moisture, well-drained soil; cut back plants that decline in summer heat; susceptible to root rot, gray mold, late blight, tobacco mosaic virus; aphids, flea beetles, slugs and snails.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a601","field":"temperatureProfile"},{"citation":"Royal Horticultural Society (RHS), Petunia genus page: grow in light, well-drained soil in full sun with shelter from drying winds; plant out after frosts have passed; sow seed at 13-18 C in early spring; flowers late spring to autumn.","url":"https://www.rhs.org.uk/plants/190790/petunia/details","field":"seasonality"},{"citation":"Confidence note: container minimum liters (8 L recommended / 11-20 L ideal) estimated from common horticultural practice (a ~10-12 inch pot per petunia; 12 inch pot is roughly 11 L) because the extension sources reviewed give container guidance qualitatively rather than in volume units. heatStressC (32 C) is a conservative estimate derived from Missouri Botanical Garden''s note that plants decline in summer heat and should be cut back; no reviewed source gives an exact heat-stress threshold. wateringProfile.baseIntervalDays of 1 reflects UMN/Almanac guidance that container petunias may need daily water in summer; in-ground plants need only a deep weekly soak.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('philodendron-hederaceum', 'Philodendron hederaceum', array['Heartleaf philodendron','Heart leaf philodendron','Sweetheart plant','Parlor ivy']::text[], 'houseplant', 'vine', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.8}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":1,"preferredNpk":"balanced (e.g. 10-10-10 or 20-20-20) houseplant fertilizer, applied lightly"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":2,"idealMaxLiters":10,"soilMixTags":["well-draining","lightweight-potting-mix","soil-based-potting-mix","moisture-retentive-but-not-soggy"]}'::jsonb, '{"targetSunHours":4,"minSunHours":0,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[3,4,5,6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot in overly moist or poorly drained soil — do not let the pot sit in water','Yellowing leaves from too much water or too little light','Brown, curled leaf tips from over-fertilizing','Spindly, stretched stems when light is too dark','Watch for aphids, spider mites, mealybugs, and scale','Leaf spots may occur','Toxic to humans and pets (calcium oxalate crystals) — keep out of reach','Avoid direct sunlight, which can burn the leaves; grow in bright indirect light']::text[], 0.9, '[{"citation":"North Carolina Extension Gardener Plant Toolbox — Philodendron hederaceum: prefers medium light, tolerates low light (deep shade <2h direct sun to partial shade 2-6h); keep soil slightly moist with good drainage, slow watering in winter; USDA zones 11a-12b; trailing or climbing tropical evergreen vine; toxic (calcium oxalate)","url":"https://plants.ces.ncsu.edu/plants/philodendron-hederaceum/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Philodendron hederaceum: winter hardy USDA zones 11-12; part shade, bright indirect light indoors, avoid direct sun; medium water, reduce fall to late winter; soil-based potting mix; root rot in overly moist soils; aphids, spider mites, mealybugs, scale; easy culture, trains on trellis or trails from hanging basket","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b611","field":"wateringProfile"},{"citation":"UF/IFAS Gardening Solutions — Heartleaf Philodendron: water when top inch of soil is dry; bright diffuse light, avoid direct sun; temperatures below 50°F (10°C) are too cool; fertilize every 3-4 months (light feeder; excess fertilizer browns/curls leaf tips); lightweight well-drained potting media; suits hanging baskets and containers","url":"https://gardeningsolutions.ifas.ufl.edu/plants/houseplants/heartleaf-philodendron/","field":"temperatureProfile"},{"citation":"Iowa State University Extension, Growing Philodendrons at Home — water when top of soil is dry, evenly moist but not wet; fertilize lightly once or twice a month during spring/summer active growth with balanced all-purpose fertilizer; home temperatures 65-80°F (18-27°C) well tolerated; grows best slightly pot-bound, repot one size up when overcrowded","url":"https://yardandgarden.extension.iastate.edu/how-to/growing-philodendrons-home","field":"feedingProfile"},{"citation":"Iowa State University Extension, Growing Philodendrons at Home — pot-size guidance: container large enough to support the top growth without toppling; does well slightly pot-bound; repot one size larger when overcrowded","url":"https://yardandgarden.extension.iastate.edu/how-to/growing-philodendrons-home","field":"containerProfile"},{"citation":"Confidence note: sources give qualitative triggers, not fixed numbers. baseIntervalDays=7 derives ''water when the top inch of soil is dry'' (UF/IFAS, Iowa State) to a typical indoor cadence. recommendedMinLiters=2 maps the standard 15 cm (6 in) starter pot / hanging basket implied by extension guidance to liters; no source states liters. heatStressC=35 is a conservative estimate above the 18-27°C comfortable range (Iowa State); feeding interval of 30 days follows Iowa State (monthly in growing season) over UF/IFAS''s every-3-4-months — both are within the lightly-fed guidance.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('rosa-x-hybrida', 'Rosa x hybrida', array['Rose','Hybrid tea rose','Garden rose']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":30,"preferredNpk":"balanced granular rose fertilizer (e.g. 10-10-10); stop feeding ~6 weeks before first frost / after August"}'::jsonb, '{"recommendedMinLiters":30,"idealMinLiters":40,"idealMaxLiters":75,"soilMixTags":["loam-based","peat-free-john-innes-no3","well-drained","slightly-acidic","high-organic-matter"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-26,"heatStressC":35,"frostSensitive":false}'::jsonb, '{"productiveMonths":[5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Black spot, powdery mildew, and rust are common fungal diseases — water at soil level in the morning and keep foliage dry (Clemson HGIC, Missouri Botanical Garden)','Rose rosette disease is a serious incurable threat in many regions (Missouri Botanical Garden)','Insect pests include aphids, thrips, beetles, borers, scale, and spider mites (Missouri Botanical Garden)','Container roses must never dry out completely or they become prone to powdery mildew; pots may need daily watering in hot summer weather (RHS)','Crowns/graft unions need winter protection (soil or mulch mound) in cold-winter climates (Missouri Botanical Garden)','Climbing rose varieties (unlike the default bush habit profiled here) require a trellis, fence, or arbor for support (Clemson HGIC)']::text[], 0.2, '[{"citation":"Clemson Cooperative Extension HGIC 1172, ''Growing Roses'' — give roses at least six to eight hours of direct sun a day; morning sun dries leaves and helps prevent disease.","url":"https://hgic.clemson.edu/factsheet/growing-roses/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC 1172, ''Growing Roses'' — fertilize when plants first leaf out, then after each bloom cycle (roughly monthly) until six weeks before the first frost; reduce rates by half June-August.","url":"https://hgic.clemson.edu/factsheet/growing-roses/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC 1172, ''Growing Roses'' — deep watering promotes deep roots; loose, well-drained, well-aerated soil with plenty of organic matter; soaker hoses keep foliage dry; climbers and ramblers need training over fences, arbors, or trellises.","url":"https://hgic.clemson.edu/factsheet/growing-roses/","field":"wateringProfile"},{"citation":"RHS, ''Roses: Growing in Containers'' — patio/miniature roses in pots 23-35 cm (9-14 in) deep; ground-cover and climbing roses minimum depth 30-45 cm (12-18 in); use peat-free John Innes No 3 compost; ensure container roses do not dry out or they become prone to powdery mildew; spring top-dressing of granular rose fertilizer, avoid feeding after August so soft growth is not damaged by winter cold.","url":"https://www.rhs.org.uk/plants/roses/growing-in-containers","field":"containerProfile"},{"citation":"RHS, ''Roses: Growing in Containers'' — position with the plant in sun for at least half the day; 5 cm top-dressing of well-rotted compost or manure for moisture retention.","url":"https://www.rhs.org.uk/plants/roses/growing-in-containers","field":"feedingProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Rosa ''Peace'' (representative hybrid tea, kempercode e284) — USDA hardiness zones 5 to 9 (zone 5 winter minimum approx. -29 to -23 C); best in full sun in medium-moisture, slightly acidic, well-drained garden loams; water deeply and regularly (mornings are best), avoid overhead watering; blooms May through frost; black spot, powdery mildew, rust, rose rosette; aphids, beetles, borers, scale, thrips, spider mites; crowns may need winter protection in cold-winter climates.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=e284","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Rosa ''Peace'' — bloom period May through frost in the St. Louis area (zone 6), supporting productive months May-October with winter dormancy December-February.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=e284","field":"seasonality"},{"citation":"Confidence note: wateringProfile.baseIntervalDays=3 with hotWeatherMultiplier=0.5 is a conservative container-oriented interpolation — sources state deep watering roughly weekly in ground but warn container roses dry fast and may need daily water in summer heat; no source gives an exact day interval. containerProfile liters are converted from RHS pot-depth dimensions (no liter figure published); 30 L minimum reflects a ~38-40 cm pot for a bush rose. temperatureProfile.coldHardyMinC=-26 is derived from the USDA zone 5 rating of a representative hybrid tea and varies by cultivar/graft (winter crown protection still advised); heatStressC=35 and rainSkipThresholdMm=12 are conservative operational estimates not stated numerically by any source. feedingProfile.baseIntervalDays=30 approximates Clemson''s ''after each bloom cycle'' cadence.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('rudbeckia-hirta', 'Rudbeckia hirta', array['Black-eyed Susan','Gloriosa Daisy','Brown-eyed Susan']::text[], 'ornamental', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.75,"rainSkipThresholdMm":6}'::jsonb, '{"baseIntervalDays":90,"containerLeachAdjustment":0.75,"preferredNpk":"12-6-6"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":15,"idealMaxLiters":30,"soilMixTags":["well-draining","general-potting-mix","moderate-fertility"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":35,"frostSensitive":false}'::jsonb, '{"productiveMonths":[6,7,8,9,10],"dormancyMonths":[11,12,1,2,3]}'::jsonb, array['Powdery mildew on foliage - water at soil level, not on leaves, and give plants air circulation','Slugs and snails damage young plants','Occasional leaf spot and rust when leaves stay wet','Aphids and Japanese beetles occasionally feed on plants','Struggles in poorly drained, constantly wet soil - ensure container drainage','Short-lived perennial or biennial - often regrown each year; it self-seeds prolifically unless deadheaded','Tall cultivars (over 60 cm) in windy spots may flop and benefit from a discreet stake, though support is normally unnecessary']::text[], 0.1, '[{"citation":"Missouri Botanical Garden Plant Finder - Rudbeckia hirta: full sun; average, medium-moisture, well-drained soil; drought tolerant; struggles in wet, poorly drained soil; USDA Zones 3-7; blooms June-September; powdery mildew and slugs/snails noted; low maintenance; biennial/short-lived perennial that blooms first year from seed","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=277225","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Rudbeckia hirta: Zone 3 to 7 hardiness; bloom June to September; deadheading prolongs bloom and limits self-seeding","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=277225","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC - Rudbeckia factsheet: full sun (greater than 6 hours of direct sunlight), tolerates partial shade; drought and heat tolerant once established; slow-release 12-6-6 fertilizer in April when growth emerges and again at half rate in September; dwarf cultivars suit containers; powdery mildew, leaf spot, rust with wet foliage; aphids, Japanese beetles, spider mites occasional","url":"https://hgic.clemson.edu/factsheet/rudbeckia/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC - Rudbeckia factsheet: full sun defined as more than 6 hours direct sun per day; adapts to partial shade","url":"https://hgic.clemson.edu/factsheet/rudbeckia/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Rudbeckia hirta: USDA Zones 3a-8b; full sun (6+ hours) or partial shade (2-6 hours); moist, well-drained soil; tolerates occasionally dry conditions, moderately drought-resistant; 2-4 ft tall, 12 in spacing; blooms late spring into mid-fall with deadheading; powdery mildew, slugs, snails","url":"https://plants.ces.ncsu.edu/plants/rudbeckia-hirta/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Rudbeckia hirta: Zones 3a-8b hardiness; biennial or short-lived perennial blooming first year from seed; bloom continues into mid-fall with deadheading","url":"https://plants.ces.ncsu.edu/plants/rudbeckia-hirta/","field":"seasonality"},{"citation":"RHS - Rudbeckia hirta (plant 68850): hardiness H3 (-5 to 1 C) when grown as a half-hardy annual; full sun or partial shade; moist but well-drained soil; 0.5-1 m tall, 0.1-0.5 m spread; biennial or short-lived perennial often grown as an annual; flowers summer to autumn","url":"https://www.rhs.org.uk/plants/68850/rudbeckia-hirta/details","field":"temperatureProfile"},{"citation":"RHS - Rudbeckia hirta: moist but well-drained conditions preferred; tolerates clay and loam","url":"https://www.rhs.org.uk/plants/68850/rudbeckia-hirta/details","field":"wateringProfile"},{"citation":"Confidence note: no authoritative source states an exact watering interval in days; baseIntervalDays=3 is a conservative container-growing estimate derived from ''medium moisture, water when soil begins to dry, drought tolerant once established'' guidance (Missouri Botanical Garden, NC State). Adjust by soil-dryness check.","field":"confidence"},{"citation":"Confidence note: container size is not specified by the cited extension sources beyond ''dwarf cultivars are ideal for containers'' (Clemson); recommendedMinLiters=11 (approx. 3 gal / 30 cm pot) is an estimate sized to the species'' 2-4 ft height and fibrous, relatively shallow root system. Larger pots improve stability and bloom.","field":"confidence"},{"citation":"Confidence note: feeding interval estimated. Clemson recommends slow-release 12-6-6 twice per season (April and September); baseIntervalDays=90 approximates that schedule. The species needs only moderate fertility - excess nitrogen reduces flowering.","field":"confidence"},{"citation":"Confidence note: heatStressC=35 is an estimate; sources describe the plant as heat tolerant (Clemson) but give no numeric threshold. coldHardyMinC=-34 reflects USDA Zone 4 as a conservative reading of the Zone 3-7/3a-8b ratings (MoBot, NC State); plants grown as half-hardy annuals from spring transplants should still be hardened off (RHS H3).","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('salvia-splendens', 'Salvia splendens', array['Salvia (scarlet)','Scarlet Sage','Bedding Sage','Salvia']::text[], 'ornamental', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":13}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.8,"preferredNpk":"balanced slow-release formulated for annuals"}'::jsonb, '{"recommendedMinLiters":7.5,"idealMinLiters":10,"idealMaxLiters":20,"soilMixTags":["well-drained","loam","high-organic-matter","compost-enriched"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":0,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"6":[{"startMonth":5,"endMonth":6}],"7":[{"startMonth":4,"endMonth":6}],"8":[{"startMonth":4,"endMonth":5}],"9":[{"startMonth":3,"endMonth":5}],"10":[{"startMonth":2,"endMonth":5}]},"productiveMonths":[6,7,8,9,10]}'::jsonb, array['Frost-tender: plant out only after all danger of frost has passed; killed by first hard frost outside zones 10-11','Not drought-tolerant — wilts quickly in dry soil, especially in containers','Avoid excessive irrigation and poorly drained soil: stem and root rots, damping-off of seedlings','Powdery mildew and Botrytis blight in humid, crowded plantings','Aphids, spider mites, and whiteflies are the most common pests','Many bedding cultivars produce little nectar and are poor pollinator resources despite attracting hummingbirds/butterflies','Appreciates light afternoon shade in very hot summer climates']::text[], 0.1, '[{"citation":"NC State Extension Gardener Plant Toolbox — Salvia splendens (Scarlet Sage): full sun (6+ hrs) to partial shade (2-6 hrs); not drought-tolerant; well-drained loam high in organic matter; hardy USDA 10a-11b, grown as annual elsewhere; suited to containers; aphids, spider mites, whiteflies, powdery mildew, botrytis, southern blight.","url":"https://plants.ces.ncsu.edu/plants/salvia-splendens/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Salvia splendens: ''It is not drought-tolerant, but it needs warmth''; regular watering, consistently moist, well-drained soil.","url":"https://plants.ces.ncsu.edu/plants/salvia-splendens/","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Salvia splendens: medium water; average, evenly moist, well-drained soils in full sun to part shade; winter hardy USDA zones 10-11, grown as warm-weather annual; set out after last frost date; 1-2 ft tall, compact cultivars 8-15 in for edging and containers.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a606","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Salvia splendens: hardy zones 10-11 only, treated as annual in St. Louis; start seed indoors 6-8 weeks before last frost, plant out after last frost (basis for frostSensitive, coldHardyMinC ~0 C, and spring planting windows).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a606","field":"temperatureProfile"},{"citation":"Old Farmer''s Almanac — Salvia growing guide: full sun 6-8 hours/day; water during summer if rainfall is less than 1 inch (25 mm) per week; salvia does not like excessive summer irrigation; garden plants need little feeding, feed container plants in spring; mix in compost at planting.","url":"https://www.almanac.com/plant/salvia","field":"wateringProfile"},{"citation":"Old Farmer''s Almanac — Salvia growing guide: 6-8 hours of sun per day and well-draining soil (basis for targetSunHours).","url":"https://www.almanac.com/plant/salvia","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC — Salvia factsheet: plant in spring after danger of frost is passed; apply a slow-release fertilizer formulated for annuals at planting; ideal in full sun, tolerates partial shade; problems include damping-off, stem/root rots, powdery mildew, Botrytis, aphids, spider mites, whiteflies.","url":"https://hgic.clemson.edu/factsheet/salvia/","field":"feedingProfile"},{"citation":"NC State Extension Plant Toolbox — bloom ''summer to frost'' (basis for productiveMonths June-October).","url":"https://plants.ces.ncsu.edu/plants/salvia-splendens/","field":"seasonality"},{"citation":"Container minimum derived from extension size data (NC State/MOBOT: 1-2 ft tall, 8-18 in spread, compact cultivars recommended for containers): a 20-25 cm (8-10 in) pot of ~7.5-10 L per plant is a conservative working minimum; extension sources confirm container suitability but publish no exact pot volume.","url":"https://plants.ces.ncsu.edu/plants/salvia-splendens/","field":"containerProfile"},{"citation":"Confidence note: containerProfile liters, feedingProfile.baseIntervalDays (monthly container feeding inferred from Clemson slow-release-at-planting + Almanac spring container feeding), watering baseIntervalDays (3 days derived from ~1 inch/week guidance plus ''not drought-tolerant'' container context), and heatStressC (35 C estimate; sources say ''heat-tolerant'' without a threshold) are conservative derivations, not directly published numbers.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('spathiphyllum-wallisii', 'Spathiphyllum wallisii', array['Peace lily','Wallis peace lily','Spath','White sails']::text[], 'houseplant', 'upright', false, null, 0, '{"baseIntervalDays":7,"dryingTolerance":"low","overwaterRisk":"high","hotWeatherMultiplier":0.8}'::jsonb, '{"baseIntervalDays":42,"containerLeachAdjustment":1,"preferredNpk":"balanced liquid houseplant fertilizer (e.g. 20-20-20) at quarter strength every 6-8 weeks in spring and summer (Clemson HGIC); RHS suggests a general balanced liquid feed every few weeks April-October; low fertility needs — overfeeding burns leaf tips and roots"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":12,"soilMixTags":["well-drained","moisture-retentive","peat-free-multipurpose","perlite-3-to-1","quality-potting-mix"]}'::jsonb, '{"targetSunHours":1,"minSunHours":0,"maxSunHours":3}'::jsonb, '{"coldHardyMinC":4,"heatStressC":30,"frostSensitive":true}'::jsonb, '{"productiveMonths":[4,5,6,7,8,9,10],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot from soggy soil or sitting in a saucer of standing water — keep moist but never waterlogged and use a pot with drainage','Dramatic drooping/wilting when the compost dries out fully — recovers within hours of a good soak, but repeated wilting yellows leaves','Brown leaf tips from over-fertilizing or excessive drying; brown leaf edges from very dry air — mist or stand on a tray of damp gravel, away from radiators and cold draughts','Failure to flower when light is too low or the plant is under about a year old — survives in shade but rarely blooms there','Direct summer sun scorches the foliage — bright indirect light only','Pests: mealybugs, scale, spider mites, fungus gnats (generally pest-light)','Contains calcium oxalate crystals — toxic to pets and children if chewed (mouth/throat burning); wear gloves when handling','Cold damage below about 4 C (40 F); growth slows below 12 C (55 F) — indoor/frost-free growing only','Prefers being slightly pot-bound; overpotting keeps the mix too wet — repot only 1-2 inches (2.5-5 cm) larger']::text[], 0.2, '[{"citation":"Clemson University HGIC — Peace Lily factsheet: tolerates low light, grows best in bright indirect light, no direct sun; keep soil moist but not soggy, dry slightly between waterings, never leave in standing water (root rot); balanced 20-20-20 liquid fertilizer at quarter strength every 6-8 weeks in spring/summer, overfertilizing burns tips; prefers 68-85 F days, ~10 F cooler nights, avoid below 60 F; likes being slightly pot-bound, repot only 1-2 in larger; pests: fungus gnats, mealybugs, spider mites, scale; calcium oxalate toxicity to pets and children; most varieties 1-4 ft","url":"https://hgic.clemson.edu/factsheet/peace-lily/","field":"feedingProfile"},{"citation":"Clemson University HGIC — Peace Lily factsheet: warm daytime 68-85 F (20-29 C), nights ~10 F cooler, avoid temperatures below 60 F to prevent cold damage; keep away from heat/AC vents","url":"https://hgic.clemson.edu/factsheet/peace-lily/","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Spathiphyllum (group), kempercode b568: zones 11-12; part shade to full shade, bright filtered light preferred, no direct sun; medium moisture, let soil dry between waterings but do not allow to wilt; 55-40 F slows growth and prolonged exposure below 40 F damages the plant; low fertility needs, fertilize at one-quarter strength; keep somewhat potbound; mealybugs and scale occasionally; 1-6 ft tall","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b568","field":"wateringProfile"},{"citation":"RHS — How to grow peace lilies: water April-October once the top few centimetres of compost are dry, reduce in winter; feed with a general liquid fertiliser every few weeks during the growing season; bright indirect light near a window, not direct summer sun; minimum 12 C (55 F), ideal 12-24 C (55-75 F); moderate humidity — damp gravel tray, mist leaves; pot only slightly larger (avoid overpotting), peat-free multi-purpose compost with perlite 3:1; new plants can stay in original pot 1-2 years; poisonous arum — gloves, keep from children and pets","url":"https://www.rhs.org.uk/plants/peace-lilies/how-to-grow-peace-lilies","field":"lightProfile"},{"citation":"RHS — How to grow peace lilies: peat-free multi-purpose compost mixed 3:1 with perlite; repot into a pot only slightly larger; container guidance backs containerProfile pot-size and soil tags","url":"https://www.rhs.org.uk/plants/peace-lilies/how-to-grow-peace-lilies","field":"containerProfile"},{"citation":"RHS — Spathiphyllum wallisii plant profile: herbaceous perennial houseplant from tropical Central America/Colombia; indirect or filtered light, partial shade under glass (deep shade reduces flowering); water and mist freely in growth, high humidity, balanced liquid fertiliser monthly; frost-free only; poisonous","url":"https://www.rhs.org.uk/plants/17623/spathiphyllum-wallisii/details","field":"seasonality"},{"citation":"Confidence note: baseIntervalDays=7 converts ''water once the top few centimetres are dry'' (RHS) / ''moist but dries slightly between waterings'' (Clemson) into a typical indoor weekly cadence — not stated as a number by any source; hotWeatherMultiplier=0.8 is a conservative planner estimate","field":"confidence"},{"citation":"Confidence note: lightProfile is expressed as DIRECT sun hours (target 1, max 3) translated from ''bright indirect light, no direct sun'' guidance — sources give qualitative light levels, not sun-hours; treat as bright-indirect placement, not outdoor sun exposure","field":"confidence"},{"citation":"Confidence note: recommendedMinLiters=2 (~15 cm pot) and ideal 3-12 L are planner conversions from ''keep slightly pot-bound, repot 1-2 in larger'' (Clemson/MoBot/RHS) and typical 1-4 ft mature size — no source states liters. heatStressC=30 derived from Clemson''s 85 F upper preferred bound; coldHardyMinC=4 from MoBot''s damage threshold below 40 F. Seasonality months derived from RHS April-October growing season for an indoor plant","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('tagetes-patula', 'Tagetes patula', array['Marigold','French Marigold']::text[], 'ornamental', 'bush', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":45,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":7.5,"idealMaxLiters":20,"soilMixTags":["well-drained","loamy","moderately-fertile","ph-6-to-7"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":1,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Tolerates drought better than wet feet; soggy or poorly drained soil leads to stem and root rots — let the soil dry somewhat between deep waterings.','Over-fertilizing produces lush foliage at the expense of blooms; marigolds are low feeders — mix a balanced fertilizer in at planting and feed only sparingly afterward.','Spider mites can flare up in hot, dry weather; aphids, slugs, leafminers, whiteflies, and thrips are occasional pests.','Spent, rain-soaked flowers can develop gray mold (Botrytis); deadhead regularly to prolong flowering and reduce disease.','Tender warm-season annual: killed by frost; plant out only after the last spring frost once soil has warmed to about 18 C (65 F).','Compact bushy habit (15-45 cm) needs no staking; pinch young plant tips for bushier growth.']::text[], 0.3, '[{"citation":"University of Minnesota Extension — Marigolds. Need full sun all day for season-long bloom; tolerate drought better than being overly wet, so soil must be well-draining; pH 6-7; general-purpose fertilizer with equal N-P-K incorporated at planting only — extra feeding reduces bloom (low feeders); plant after soil reaches 65 F / frost danger passes; bloom up until frost; deadheading optional but encourages bloom; pinch young plants for bushiness.","url":"https://extension.umn.edu/flowers/marigolds","field":"lightProfile,wateringProfile,feedingProfile,temperatureProfile,commonIssues"},{"citation":"Clemson Cooperative Extension HGIC — How to Grow and Care for Marigolds in South Carolina. Full sun (6+ hours daily); about 1 inch of water per week once established, watered deeply once weekly with soil allowed to dry somewhat between waterings; well-drained loamy soil pH 5.5-7.0; French types 6 in - 3 ft tall, spaced 8-10 in apart; suitable for containers; plant after last spring frost; blooms early summer until hard frost; pests include spider mites, slugs, leafminers, aphids, whiteflies, thrips; fungal stem/root rots and gray mold; deadhead for continued bloom.","url":"https://hgic.clemson.edu/factsheet/marigold/","field":"lightProfile,wateringProfile,containerProfile,seasonality,commonIssues"},{"citation":"University of Wisconsin-Madison Horticulture Extension — Marigolds. Full sun (6-8 hours direct); moderate water with even moisture but no waterlogging; well-drained soil pH 6-7; low feeders not requiring heavy fertilization; direct-seed once soil exceeds 65 F (~18 C) or transplant after frost danger; deadhead spent blooms; French marigold roots release alpha-terthienyl, toxic to root-knot nematodes.","url":"https://hort.extension.wisc.edu/articles/marigolds/","field":"lightProfile,wateringProfile,feedingProfile,temperatureProfile"},{"citation":"RHS — Tagetes patula (French marigold). Hardiness H2 (tolerates low temperatures of about 1-5 C but not freezing — frost tender); full sun; moderately fertile, moist but well-drained to well-drained soil (clay, loam, or sand); height and spread 0.1-0.5 m in one year; suitable for patios and containers; water freely in dry spells; deadhead regularly to prolong flowering; generally pest- and disease-free.","url":"https://www.rhs.org.uk/plants/105531/tagetes-patula/details","field":"temperatureProfile,containerProfile,wateringProfile,lightProfile"},{"citation":"Confidence note: No extension/RHS source gives exact container volumes for Tagetes patula; recommendedMinLiters (4 L, roughly a 6-8 in pot for one compact plant), idealMinLiters (7.5 L) and idealMaxLiters (20 L, multi-plant trough) are conservative estimates anchored to RHS/Clemson ''suitable for containers'' and the plant''s 15-45 cm size. wateringProfile.baseIntervalDays (3) interprets Clemson''s ''about 1 inch per week, deeply once weekly, dry somewhat between'' for smaller container volumes; hotWeatherMultiplier and rainSkipThresholdMm are care-engine estimates. feedingProfile.baseIntervalDays (45) is a deliberately sparse container-feeding cadence consistent with UMN/UW ''low feeder, fertilize at planting only'' guidance, not an explicitly published interval. heatStressC (35) is a conservative estimate — French marigolds bloom through summer heat and no source states an explicit heat-stress threshold.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('viola-x-wittrockiana', 'Viola x wittrockiana', array['Pansy','Garden Pansy','Lady''s Delight']::text[], 'ornamental', 'rosette', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":18,"containerLeachAdjustment":0.7,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":5,"idealMinLiters":8,"idealMaxLiters":15,"soilMixTags":["well-drained","organically-rich","potting-mix","slightly-acidic"]}'::jsonb, '{"targetSunHours":5,"minSunHours":4,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":-4,"heatStressC":24,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"3-8":[{"startMonth":3,"endMonth":4},{"startMonth":8,"endMonth":9}],"9-10":[{"startMonth":10,"endMonth":11}]},"productiveMonths":[3,4,5,6,10,11],"dormancyMonths":[7,8]}'::jsonb, array['Heat-intolerant: plants get leggy and decline once temperatures stay above roughly 24C (75F); commonly removed and replaced when summer heat arrives.','Susceptible to fungal leaf spots, black root/stem rot, anthracnose, powdery mildew, scab, rust and smut, especially in wet or poorly drained conditions.','Avoid watering in late afternoon or evening and avoid overhead watering, as wet foliage encourages disease.','Avoid high-nitrogen fertilizers, which increase rot susceptibility; a balanced-to-low-N feed such as 5-10-10 is preferred.','Pests include aphids, spider mites, slugs, snails, cutworms and various caterpillars; deer, rabbits and squirrels may browse foliage and flowers.','Container minimum reflects a small, portable pot (about 30 cm / 12 in diameter or less) so plants can be moved to cooler shade as the sun intensifies; pansies are small (15-25 cm tall) and do not need a large root volume.']::text[], 0.5, '[{"citation":"Missouri Botanical Garden Plant Finder - Viola x wittrockiana: full sun to part shade (part afternoon shade in St. Louis), medium/consistently moist well-drained humus-rich soil, USDA zones 6-10, height 0.50-0.75 ft, bloom April-June, short-lived perennial grown as cool-season annual, succumbs to summer heat, susceptible to fungal leaf diseases and slugs/snails, used in window boxes and containers.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a616","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Viola x wittrockiana: humus-rich, consistently moist, well-drained soil; medium water needs; container and window-box suitable; small habit ~6-9 in tall.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a616","field":"containerProfile"},{"citation":"Missouri Botanical Garden Plant Finder - Viola x wittrockiana: plants succumb to summer heat and should be removed when temperatures rise; grown as cool-season annual; susceptible to fungal leaf diseases, slugs and snails.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a616","field":"commonIssues"},{"citation":"Clemson HGIC ''Pansies and Johnny-Jump-Ups'' - rich well-draining soil with organic matter, pH 5.4-5.8; water ~1 inch per week (continue when less than 1 inch of rain falls weekly); never water late afternoon/evening; avoid overhead watering; apply 5-10-10 in late fall and early spring; avoid high-nitrogen fertilizers; spacing 6-8 in (small-flowered) to 10-12 in (large-flowered); 2 in organic mulch; diseases include black root rot and fungal leaf spots; pests aphids, spider mites, slugs.","url":"https://hgic.clemson.edu/factsheet/pansies-and-johnny-jump-ups/","field":"wateringProfile"},{"citation":"Clemson HGIC ''Pansies and Johnny-Jump-Ups'' - fertilizer: mix granular slow-release at planting or apply 5-10-10 in late fall and early spring; avoid high-nitrogen formulas (increase rot susceptibility).","url":"https://hgic.clemson.edu/factsheet/pansies-and-johnny-jump-ups/","field":"feedingProfile"},{"citation":"Clemson HGIC ''Pansies, Violas, and Panolas'' - plant in fall in full sun and organically rich well-drained soil; water-soluble liquid fertilizer every two to three weeks; pansies flower less in extreme cold; avoid moisture-retention potting mixes in wet winters to prevent root rot; deer, rabbits and squirrels browse plants.","url":"https://hgic.clemson.edu/pansies-violas-and-panolas-oh-my/","field":"feedingProfile"},{"citation":"UF/IFAS FPS-609 Viola x wittrockiana - part shade/part sun with shade during hot weather; needs ample moisture; tolerates clay, sand, acidic and loam soils, prefers rich soil; height 0.5-1 ft, spread 0.5-1 ft, round spreading form; thrives in winter in zones 8-11, not suitable for summer there; seed germinates 10-14 days at 65-75F; pests include aphids, cutworms, slugs, mites; diseases anthracnose, leaf spots, powdery mildew, scab, stem rot, rust, smut; used in containers, planters, edging, borders; spacing 6-12 in.","url":"https://ask.ifas.ufl.edu/publication/FP609","field":"commonIssues"},{"citation":"Old Farmer''s Almanac ''Pansies'' - hardy in USDA zones 3-8; full sun to part shade; keep soil consistently moist, water when the top inch of soil feels dry; heavy feeders, fertilize with water-soluble liquid fertilizer every two to three weeks; tolerate light frost and temperatures to about 25F (-4C); get leggy in summer heat (decline above ~75F/24C); grow best at soil temperatures 45-65F (7-18C); plant in early spring or fall; portable containers 12 in diameter or less recommended so plants can be moved to cooler areas.","url":"https://www.almanac.com/plant/pansies","field":"temperatureProfile"},{"citation":"Old Farmer''s Almanac ''Pansies'' - watering: keep soil consistently moist but not soggy, water when the top inch of soil feels dry, especially during dry spells; container soil dries faster than garden soil; light: full sun to part shade.","url":"https://www.almanac.com/plant/pansies","field":"wateringProfile"},{"citation":"Old Farmer''s Almanac ''Pansies'' - portable containers 12 inches or less in diameter recommended (about 5 liters minimum) so plants can be moved to cooler shade; standard potting soil; light: full sun to part shade with morning sun preferred.","url":"https://www.almanac.com/plant/pansies","field":"containerProfile"},{"citation":"Confidence note: baseIntervalDays=3 is a conservative interpretation of ''water when the top inch is dry'' / ''~1 inch per week'' (Almanac, Clemson); actual interval varies with weather/pot size. feedingProfile baseIntervalDays=18 is the midpoint of the cited ''every two to three weeks'' (14-21 days) liquid-feed guidance (Almanac, Clemson). Light targetSunHours=5 is a mid-range estimate for the cited ''full sun to part shade / morning sun with afternoon shade in heat'' (no exact hour count is published). containerProfile liters are estimated from the cited ''12-inch-or-less diameter portable pot'' since extensions give pot diameter, not volume. verticalSuitability=0.5 reflects documented suitability for window boxes and hanging containers without an authoritative numeric rating.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('zamioculcas-zamiifolia', 'Zamioculcas zamiifolia', array['ZZ plant','Zanzibar gem','Aroid palm','Eternity plant']::text[], 'houseplant', 'upright', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.9}'::jsonb, '{"baseIntervalDays":90,"preferredNpk":"balanced (e.g. 10-10-10) at half strength, growing season only"}'::jsonb, '{"recommendedMinLiters":3,"idealMinLiters":4,"idealMaxLiters":15,"soilMixTags":["well-draining","peat-or-coir-based","perlite","sand","cactus-succulent-mix"]}'::jsonb, '{"targetSunHours":2,"minSunHours":0,"maxSunHours":4}'::jsonb, '{"coldHardyMinC":15,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"dormancyMonths":[11,12,1,2]}'::jsonb, array['Overwatering is the main killer — rhizomes and roots rot quickly in wet soil; always let the potting mix dry completely before watering','Direct sun can scorch/scald the glossy leaflets; keep out of full sunlight','Yellowing lower leaves usually signal overwatering, not drought','Watch for scale insects (otherwise few pest or disease problems)','All parts contain calcium oxalate — toxic to cats, dogs, and people if chewed; wash hands after handling','Black spots on stems are normal for this species, not disease','Very slow grower; repot only every 2-3 years in spring, going up one pot size']::text[], 0.1, '[{"citation":"Clemson University HGIC, ''ZZ Plant (Zamioculcas zamiifolia): Indoor Care, Growing Tips & Plant Guide'' — water 1-2 times a month only after the potting medium has completely dried; overwatering causes root rot","url":"https://hgic.clemson.edu/factsheet/zz-plant-zamioculcas-zamiifolia-indoor-care-growing-tips-plant-guide/","field":"wateringProfile"},{"citation":"NC State Extension Plant Toolbox, Zamioculcas zamiifolia — water twice monthly in summer (only if soil has dried out completely) and once a month in winter when not actively growing","url":"https://plants.ces.ncsu.edu/plants/zamioculcas-zamiifolia/","field":"wateringProfile"},{"citation":"Clemson University HGIC — fertilize only once or twice during the growing season with a balanced fertilizer; ~90-day interval encodes this growing-season-only cadence","url":"https://hgic.clemson.edu/factsheet/zz-plant-zamioculcas-zamiifolia-indoor-care-growing-tips-plant-guide/","field":"feedingProfile"},{"citation":"NC State Extension Plant Toolbox — deep shade (less than 2 hours direct sun) to partial shade (2-6 hours); thrives in bright indirect light; direct rays can scald leaves","url":"https://plants.ces.ncsu.edu/plants/zamioculcas-zamiifolia/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Zamioculcas zamiifolia (Kemper code d179) — part shade to full shade; bright indirect light; USDA Zones 9-10; bring indoors when temperatures dip below 60 F (~15.5 C); 2-3 ft tall and wide","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=d179","field":"lightProfile"},{"citation":"Clemson University HGIC — sensitive to cold, keep above 60 F (~15.5 C); coldHardyMinC 15 is the conservative keep-above threshold for container culture, not the absolute survival minimum","url":"https://hgic.clemson.edu/factsheet/zz-plant-zamioculcas-zamiifolia-indoor-care-growing-tips-plant-guide/","field":"temperatureProfile"},{"citation":"Clemson University HGIC — soil mix of 50% peat moss or coir-based potting soil, 25% perlite, 25% sand; good drainage essential, never leave standing water","url":"https://hgic.clemson.edu/factsheet/zz-plant-zamioculcas-zamiifolia-indoor-care-growing-tips-plant-guide/","field":"containerProfile"},{"citation":"NC State Extension Plant Toolbox — slow growth rate, 2-4 ft tall and wide; medium toxicity to cats and dogs (calcium oxalate); watch for scale insects","url":"https://plants.ces.ncsu.edu/plants/zamioculcas-zamiifolia/","field":"commonIssues"},{"citation":"Confidence note: container liters (3 L minimum ≈ 6-inch nursery pot; ideal 4-15 L ≈ 7-12-inch pots) are estimated from the plant''s slow growth, mature 2-3 ft size (MoBot/NCSU), and common nursery pot sizes — no extension source states an explicit pot volume","field":"confidence"},{"citation":"Confidence note: heatStressC 35 and hotWeatherMultiplier 0.9 are conservative estimates — extension sources document cold limits (keep above 60 F) but give no explicit upper heat-stress temperature; ZZ tolerates warm indoor conditions well","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('zinnia-elegans', 'Zinnia elegans', array['Zinnia','Common zinnia','Youth-and-old-age']::text[], 'ornamental', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"balanced (e.g. 10-10-10) at planting, then monthly higher-phosphorus or high-potassium bloom feed"}'::jsonb, '{"recommendedMinLiters":4,"idealMinLiters":8,"idealMaxLiters":20,"soilMixTags":["well-drained","organic-matter-rich","loamy"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":5,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"7":[{"startMonth":4,"endMonth":6}]},"productiveMonths":[6,7,8,9,10]}'::jsonb, array['Highly susceptible to powdery mildew; water at the base, never overhead, and ensure good air circulation (UMN, Clemson).','Also prone to Alternaria blight, bacterial leaf spot, root rots, Botrytis and damping-off in cold wet conditions; slugs damage young plants (Missouri Botanical Garden, RHS).','Overwatering and wet foliage promote fungal disease; only water when the top 2.5-5 cm of soil are dry (UMN, Clemson).','Frost-tender warm-season annual: do not plant out until soil reaches ~21C and all frost danger has passed; killed by frost (UMN, Clemson, RHS).','Tall cultivars (60-120 cm) benefit from netting or support secured at ~30-40 cm above ground; dwarf cultivars are best for containers — extension guidance notes zinnias perform better in beds than containers (RHS, UMN).','Deadhead spent blooms to extend flowering and pinch young plants for a bushier habit (Clemson, Missouri Botanical Garden).']::text[], 0.1, '[{"citation":"University of Minnesota Extension — Zinnia. Full sun 8+ hours/day in a very warm location; water only when the top 1-2 inches of soil are dry; performs better in garden beds than containers.","url":"https://extension.umn.edu/flowers/zinnia","field":"lightProfile"},{"citation":"University of Minnesota Extension — Zinnia. ''Only water when the top 1 to 2 inches of soil are dry''; avoid overwatering and wet foliage, which promote fungal disease (powdery mildew).","url":"https://extension.umn.edu/flowers/zinnia","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Zinnia. General-purpose fertilizer (equal N-P-K) at planting, then monthly applications of a higher-phosphorus formula to promote new blooms (basis for baseIntervalDays=30 and preferredNpk).","url":"https://extension.umn.edu/flowers/zinnia","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Zinnia. Direct seeding requires soil temperature of at least 70F (21C); transplants acceptable at 60F (16C); germination 70-75F; frost-tender annual planted after last frost.","url":"https://extension.umn.edu/flowers/zinnia","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC — How to Grow Zinnias: The Best Varieties & Care Tips. Full sun (6+ hours); about 1 inch (25 mm) of water per week applied at the base, watering when the top 1-2 inches of soil feel dry; sow after last frost with soil/air around 70F; spacing 8-24 inches; powdery mildew, Alternaria and bacterial leaf spot.","url":"https://hgic.clemson.edu/factsheet/how-to-grow-zinnias-the-best-varieties-care-tips/","field":"wateringProfile"},{"citation":"Clemson Cooperative Extension HGIC — How to Grow Zinnias. Full sun, minimum 6 hours of direct sun (basis for minSunHours=6); deadheading extends the bloom season; suitable for containers using dwarf cultivars.","url":"https://hgic.clemson.edu/factsheet/how-to-grow-zinnias-the-best-varieties-care-tips/","field":"lightProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Zinnia elegans (Kemper Code a618). Annual grown in USDA zones 2-11; full sun; medium water; humusy, evenly moist, well-drained soils; height 1-4 ft, spread 0.75-1 ft, upright bushy habit; blooms June to frost; plant after last frost date; susceptible to powdery mildew, leaf spots, root rots, blight, Botrytis and Japanese beetles; pinch young plants for compact bushy form.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a618","field":"seasonality"},{"citation":"Missouri Botanical Garden Plant Finder — Zinnia elegans. Upright, branching annual, not a climber or trailer (basis for growthHabit=upright and low verticalSuitability); disease-resistant cultivars recommended in hot, humid climates.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=a618","field":"growthHabit"},{"citation":"RHS Growing Guide — How to grow zinnia. Half-hardy annual that won''t tolerate cold; plant out only after all frost danger (normally June in the UK); sow at 20C and grow on at 15-18C; keep watered in hot dry weather without wetting foliage; container plants benefit from a high-potassium feed (e.g. tomato feed) while flowering, in-ground plants need no supplemental feeding; tall varieties supported by netting secured ~30-40 cm above ground; alternaria blight, botrytis, damping-off and slugs are the main problems.","url":"https://www.rhs.org.uk/plants/zinnia/growing-guide","field":"temperatureProfile"},{"citation":"RHS Growing Guide — How to grow zinnia. Container-grown zinnias fed during flowering with high-potassium feed; supports containerLeachAdjustment and the bloom-feed half of preferredNpk; support guidance for tall cultivars (requiresSupport stays false because typical/dwarf container cultivars are self-supporting).","url":"https://www.rhs.org.uk/plants/zinnia/growing-guide","field":"feedingProfile"},{"citation":"Estimated/conservative values not stated verbatim by any source: baseIntervalDays=3 translates Clemson/UMN ''~1 inch per week, water when top 1-2 in of soil are dry'' into a practical check interval (containers dry faster than beds); hotWeatherMultiplier=1.5 and rainSkipThresholdMm=12 (~0.5 in) are conservative defaults derived from the 1-inch/week guidance; coldHardyMinC=5 and heatStressC=38 are inferred warm-season-annual bounds (sources state >=21C soil preferred, frost-killed, very heat tolerant) rather than published thresholds; container volumes (4 L min ~ a 20 cm pot for one dwarf plant, 8-20 L ideal) are converted from common pot sizes — extension sources confirm container suitability for dwarf cultivars but publish no explicit volume; plantingWindowsByZone are illustrative after-last-frost windows (zone 5 ~May-Jun, zone 7 ~Apr-Jun).","url":"https://hgic.clemson.edu/factsheet/how-to-grow-zinnias-the-best-varieties-care-tips/","field":"confidence"}]'::jsonb, 1, '2026-06-02')
